import React, { useState, useCallback, useRef, useEffect } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import Header from './components/Header';
import MouthAnimation from './components/MouthAnimation';
import { PHONEMES, TEACHER_SYSTEM_PROMPT } from './constants';
import { PhonemeInfo, TranscriptionItem } from './types';
import { encode, decode, decodeAudioData, floatTo16BitPCM } from './services/audioUtils';

const App: React.FC = () => {
  const [selectedPhoneme, setSelectedPhoneme] = useState<PhonemeInfo>(PHONEMES[0]);
  const [isRecording, setIsRecording] = useState(false);
  const [transcriptions, setTranscriptions] = useState<TranscriptionItem[]>([]);
  const [teacherFeedback, setTeacherFeedback] = useState<string>("老師正在聽你練習喔！準備好了就點擊下方按鈕開始吧。");
  const [isAiSpeaking, setIsAiSpeaking] = useState(false);

  // Refs for audio processing
  const audioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const sessionRef = useRef<any>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const scriptProcessorRef = useRef<ScriptProcessorNode | null>(null);

  const cleanup = useCallback(() => {
    if (sessionRef.current) {
      sessionRef.current = null;
    }
    if (scriptProcessorRef.current) {
      scriptProcessorRef.current.disconnect();
      scriptProcessorRef.current = null;
    }
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
    sourcesRef.current.forEach(source => source.stop());
    sourcesRef.current.clear();
    setIsRecording(false);
    setIsAiSpeaking(false);
  }, []);

  const toggleRecording = async () => {
    if (isRecording) {
      cleanup();
      return;
    }

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

      if (!audioContextRef.current) {
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      }
      if (!outputAudioContextRef.current) {
        outputAudioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      }

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          systemInstruction: TEACHER_SYSTEM_PROMPT + `\nCurrently practicing: ${selectedPhoneme.ipa}. Example words: ${selectedPhoneme.exampleWords.join(', ')}. Tips: ${selectedPhoneme.tips}`,
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } },
          },
          inputAudioTranscription: {},
          outputAudioTranscription: {},
        },
        callbacks: {
          onopen: () => {
            setIsRecording(true);
            const source = audioContextRef.current!.createMediaStreamSource(stream);
            const scriptProcessor = audioContextRef.current!.createScriptProcessor(4096, 1, 1);
            scriptProcessorRef.current = scriptProcessor;

            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const pcmData = floatTo16BitPCM(inputData);
              const base64Data = encode(pcmData);

              sessionPromise.then(session => {
                session.sendRealtimeInput({
                  media: {
                    data: base64Data,
                    mimeType: 'audio/pcm;rate=16000'
                  }
                });
              });
            };

            source.connect(scriptProcessor);
            scriptProcessor.connect(audioContextRef.current!.destination);
          },
          onmessage: async (message: LiveServerMessage) => {
            // Handle Transcriptions
            if (message.serverContent?.inputTranscription) {
              const text = message.serverContent.inputTranscription.text;
              setTranscriptions(prev => [...prev, { role: 'user', text, timestamp: Date.now() }]);
            }
            if (message.serverContent?.outputTranscription) {
              const text = message.serverContent.outputTranscription.text;
              setTeacherFeedback(text);
              setTranscriptions(prev => [...prev, { role: 'model', text, timestamp: Date.now() }]);
            }

            // Handle Audio Output
            const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64Audio) {
              setIsAiSpeaking(true);
              const outCtx = outputAudioContextRef.current!;
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outCtx.currentTime);

              const audioBuffer = await decodeAudioData(decode(base64Audio), outCtx, 24000, 1);
              const source = outCtx.createBufferSource();
              source.buffer = audioBuffer;
              source.connect(outCtx.destination);

              source.onended = () => {
                sourcesRef.current.delete(source);
                if (sourcesRef.current.size === 0) setIsAiSpeaking(false);
              };

              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += audioBuffer.duration;
              sourcesRef.current.add(source);
            }

            if (message.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => s.stop());
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
              setIsAiSpeaking(false);
            }
          },
          onerror: (e) => {
            console.error('Gemini error:', e);
            cleanup();
          },
          onclose: () => {
            cleanup();
          }
        }
      });

      sessionRef.current = await sessionPromise;
    } catch (err) {
      console.error('Failed to start recording:', err);
      alert('無法開啟麥克風或連線 API。請檢查權限。');
    }
  };

  return (
    <div className="min-h-screen flex flex-col bg-orange-50/30">
      <Header />

      <main className="flex-1 max-w-5xl mx-auto w-full p-4 md:p-8 flex flex-col gap-8">
        {/* Intro Section */}
        <div className="text-center">
          <h2 className="text-3xl font-bold text-gray-800 mb-2">
            Phonics AI 發音教練
          </h2>
          <p className="text-gray-500 max-w-lg mx-auto">
            赫穠老師陪你一起練好英文基礎。選一個發音，看著嘴型，然後試著唸唸看！
          </p>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          {/* Left: Phoneme Selection */}
          <div className="lg:col-span-1 space-y-4">
            <h3 className="text-lg font-bold text-gray-700 px-2 flex items-center gap-2">
              <span className="w-2 h-6 bg-orange-400 rounded-full"></span>
              練習課程
            </h3>
            <div className="space-y-3">
              {PHONEMES.map((p) => (
                <button
                  key={p.id}
                  onClick={() => !isRecording && setSelectedPhoneme(p)}
                  disabled={isRecording}
                  className={`w-full text-left p-4 rounded-2xl border-2 transition-all flex items-center justify-between group ${
                    selectedPhoneme.id === p.id 
                      ? 'border-orange-500 bg-orange-50 shadow-md' 
                      : 'border-white bg-white/60 hover:border-orange-200'
                  } ${isRecording ? 'opacity-50 cursor-not-allowed' : ''}`}
                >
                  <div>
                    <span className="text-2xl font-bold text-orange-600 block">{p.ipa}</span>
                    <span className="text-sm text-gray-500">{p.description}</span>
                  </div>
                  <div className={`p-2 rounded-full ${selectedPhoneme.id === p.id ? 'bg-orange-500 text-white' : 'bg-gray-100 text-gray-400'}`}>
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                      <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" clipRule="evenodd" />
                    </svg>
                  </div>
                </button>
              ))}
            </div>

            <div className="bg-white/80 p-5 rounded-3xl border border-orange-100 shadow-sm mt-8">
              <h4 className="font-bold text-gray-700 mb-2 flex items-center gap-2">
                <span className="text-orange-500">💡</span> 老師的悄悄話
              </h4>
              <p className="text-sm text-gray-600 leading-relaxed italic">
                {selectedPhoneme.tips}
              </p>
            </div>
          </div>

          {/* Middle: Mouth Animation & Visual Feedback */}
          <div className="lg:col-span-2 space-y-6">
            <div className="bg-white p-8 rounded-[2.5rem] shadow-xl border border-orange-50 relative overflow-hidden">
              {/* Decorative circle */}
              <div className="absolute -top-12 -right-12 w-32 h-32 bg-orange-100/50 rounded-full blur-2xl"></div>

              <div className="flex flex-col items-center gap-8">
                <div className="text-center">
                  <span className="text-5xl font-black text-orange-500 mb-2 block">{selectedPhoneme.ipa}</span>
                  <div className="flex gap-4">
                    {selectedPhoneme.exampleWords.map(word => (
                      <span key={word} className="px-3 py-1 bg-gray-100 rounded-full text-sm font-medium text-gray-600">{word}</span>
                    ))}
                  </div>
                </div>

                <MouthAnimation 
                  state={selectedPhoneme.animationState} 
                  isActive={isAiSpeaking || isRecording} 
                />

                <div className="w-full max-w-md bg-orange-50/50 border border-orange-100 p-6 rounded-3xl text-center relative">
                   {isAiSpeaking && (
                     <div className="absolute -top-3 left-1/2 -translate-x-1/2 flex items-center gap-1">
                        {[1,2,3,4,5].map(i => (
                          <div key={i} className={`w-1 h-3 bg-orange-400 rounded-full animate-bounce`} style={{ animationDelay: `${i * 0.1}s` }}></div>
                        ))}
                     </div>
                   )}
                   <p className="text-gray-700 font-medium leading-relaxed">
                     {teacherFeedback || "正在等待你的聲音..."}
                   </p>
                </div>

                <div className="flex flex-col items-center gap-4 w-full">
                  <button
                    onClick={toggleRecording}
                    className={`group relative flex items-center justify-center w-20 h-20 rounded-full transition-all duration-300 transform active:scale-95 ${
                      isRecording 
                        ? 'bg-red-500 shadow-red-200 shadow-2xl scale-110' 
                        : 'bg-orange-500 shadow-orange-200 shadow-xl hover:scale-105'
                    }`}
                  >
                    {isRecording ? (
                      <div className="w-8 h-8 bg-white rounded-md animate-pulse"></div>
                    ) : (
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
                      </svg>
                    )}
                  </button>
                  <p className={`text-sm font-bold tracking-widest ${isRecording ? 'text-red-500 animate-pulse' : 'text-gray-400'}`}>
                    {isRecording ? '老師正在聽...' : '點擊開始練習'}
                  </p>
                </div>
              </div>
            </div>

            {/* Transcription History (Mini) */}
            <div className="bg-white/50 border border-white p-6 rounded-3xl max-h-48 overflow-y-auto space-y-2">
              <h4 className="text-xs font-bold text-gray-400 uppercase tracking-widest mb-4">發音對話紀錄</h4>
              {transcriptions.length === 0 ? (
                <p className="text-sm text-gray-400 italic">尚未開始對話...</p>
              ) : (
                transcriptions.map((item, idx) => (
                  <div key={idx} className={`flex gap-3 text-sm ${item.role === 'model' ? 'justify-start' : 'justify-end'}`}>
                    <div className={`max-w-[80%] p-3 rounded-2xl ${item.role === 'model' ? 'bg-white text-gray-600' : 'bg-orange-500 text-white'}`}>
                      {item.text}
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>
        </div>
      </main>

      <footer className="p-8 text-center text-xs text-gray-400 border-t border-orange-50 mt-12">
        <p>© 2025 赫穠教育文化 Sound Strong Education. Powered by Gemini AI.</p>
      </footer>
    </div>
  );
};

export default App;

