                  transcriptions.map((item, idx) => (
                    <div key={idx} className={`flex ${item.role === 'model' ? 'justify-start' : 'justify-end'}`}>
                      <div className={`max-w-[85%] p-4 rounded-3xl text-sm shadow-sm transition-all hover:shadow-md ${
                        item.role === 'model' 
                          ? 'bg-white text-gray-600 rounded-tl-none border border-orange-50' 
                          : 'bg-gradient-to-br from-orange-400 to-orange-500 text-white rounded-tr-none font-bold'
                      }`}>
                        {item.text}
                      </div>
                    </div>
                  ))
                )}
              </div>
            </div>
          </div>
        </div>
      </main>

      <style dangerouslySetInnerHTML={{ __html: `
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #fed7aa; border-radius: 10px; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #fb923c; }
      `}} />

      <footer className="p-10 text-center border-t border-orange-100 bg-white/30 backdrop-blur-sm mt-12">
        <p className="text-xs font-bold text-gray-400 uppercase tracking-widest">© 2025 赫穠教育文化 Sound Strong Education</p>
        <p className="text-[10px] text-gray-300 mt-2 font-medium">Powered by Gemini 2.5 Multi-modal Native Audio API</p>
      </footer>
    </div>
  );
};

export default App;

