import React, { useState, useCallback, useRef, useMemo, useEffect } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import Header from './components/Header';
import MouthAnimation from './components/MouthAnimation';
import GamificationPanel from './components/GamificationPanel';
import { PHONEMES, TEACHER_SYSTEM_PROMPT, BADGES } from './constants';
import { PhonemeInfo, TranscriptionItem, PhonemeType, UserProgress } from './types';
import { encode, decode, decodeAudioData, floatTo16BitPCM } from './services/audioUtils';

const STORAGE_KEY = 'sound_strong_user_progress';

const DEFAULT_PROGRESS: UserProgress = {
  points: 0,
  level: 1,
  streak: 0,
  lastPracticeDate: null,
  badges: [],
  sessionsCount: 0,
};

const App: React.FC = () => {
  const [selectedPhoneme, setSelectedPhoneme] = useState<PhonemeInfo>(PHONEMES[0]);
  const [isRecording, setIsRecording] = useState(false);
  const [transcriptions, setTranscriptions] = useState<TranscriptionItem[]>([]);
  const [teacherFeedback, setTeacherFeedback] = useState<string>("老師正在聽你練習喔！準備好了就點擊下方按鈕開始吧。");
  const [isAiSpeaking, setIsAiSpeaking] = useState(false);
  const [showAchievements, setShowAchievements] = useState(false);

  // Gamification State
  const [progress, setProgress] = useState<UserProgress>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : DEFAULT_PROGRESS;
  });

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(progress));
  }, [progress]);

  // Grouping phonemes for better UX
  const categorizedPhonemes = useMemo(() => {
    return {
      consonants: PHONEMES.filter(p => p.type === PhonemeType.CONSONANT),
      vowels: PHONEMES.filter(p => p.type === PhonemeType.VOWEL),
    };
  }, []);

  // Refs for audio processing
  const audioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const sessionRef = useRef<any>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const scriptProcessorRef = useRef<ScriptProcessorNode | null>(null);

  const cleanup = useCallback(() => {
    if (sessionRef.current) {
      sessionRef.current = null;
    }
    if (scriptProcessorRef.current) {
      scriptProcessorRef.current.disconnect();
      scriptProcessorRef.current = null;
    }
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
    sourcesRef.current.forEach(source => source.stop());
    sourcesRef.current.clear();
    setIsRecording(false);
    setIsAiSpeaking(false);
  }, []);

  const awardPoints = useCallback((amount: number, reason: string) => {
    setProgress(prev => {
      const newPoints = prev.points + amount;
      const newLevel = Math.floor(newPoints / 500) + 1;
      const newBadges = [...prev.badges];

      // Badge check logic
      if (!newBadges.includes('first_step')) newBadges.push('first_step');
      if (amount >= 50 && !newBadges.includes('perfect_score')) newBadges.push('perfect_score');

      return {
        ...prev,
        points: newPoints,
        level: newLevel,
        badges: newBadges,
      };
    });
  }, []);

  const toggleRecording = async () => {
    if (isRecording) {
      cleanup();
      return;
    }

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

      if (!audioContextRef.current) {
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      }
      if (!outputAudioContextRef.current) {
        outputAudioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      }

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          systemInstruction: TEACHER_SYSTEM_PROMPT + 
            `\n練習主題：${selectedPhoneme.ipa}\n` +
            `示範單字：${selectedPhoneme.exampleWords.join(', ')}\n` +
            `發音祕訣：${selectedPhoneme.tips}\n` +
            `常見錯誤：${selectedPhoneme.commonMistakes}`,
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } },
          },
          inputAudioTranscription: {},
          outputAudioTranscription: {},
        },
        callbacks: {
          onopen: () => {
            setIsRecording(true);
            const source = audioContextRef.current!.createMediaStreamSource(stream);
            const scriptProcessor = audioContextRef.current!.createScriptProcessor(4096, 1, 1);
            scriptProcessorRef.current = scriptProcessor;

            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const pcmData = floatTo16BitPCM(inputData);
              const base64Data = encode(pcmData);

              sessionPromise.then(session => {
                session.sendRealtimeInput({
                  media: {
                    data: base64Data,
                    mimeType: 'audio/pcm;rate=16000'
                  }
                });
              });
            };

            source.connect(scriptProcessor);
            scriptProcessor.connect(audioContextRef.current!.destination);

            // Increment session count
            setProgress(prev => ({
              ...prev,
              sessionsCount: prev.sessionsCount + 1,
              streak: prev.streak + 1 // Simple streak for demo
            }));
          },
          onmessage: async (message: LiveServerMessage) => {
            if (message.serverContent?.inputTranscription) {
              const text = message.serverContent.inputTranscription.text;
              setTranscriptions(prev => [...prev, { role: 'user', text, timestamp: Date.now() }]);
            }
            if (message.serverContent?.outputTranscription) {
              const text = message.serverContent.outputTranscription.text;
              setTeacherFeedback(text);
              setTranscriptions(prev => [...prev, { role: 'model', text, timestamp: Date.now() }]);

              // Gamification heuristic: if feedback is positive, award more points
              if (text.includes('👏') || text.includes('棒') || text.includes('標準')) {
                awardPoints(50, 'Perfect Pronunciation');
              } else {
                awardPoints(10, 'Practice Participation');
              }
            }

            const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64Audio) {
              setIsAiSpeaking(true);
              const outCtx = outputAudioContextRef.current!;
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outCtx.currentTime);

              const audioBuffer = await decodeAudioData(decode(base64Audio), outCtx, 24000, 1);
              const source = outCtx.createBufferSource();
              source.buffer = audioBuffer;
              source.connect(outCtx.destination);

              source.onended = () => {
                sourcesRef.current.delete(source);
                if (sourcesRef.current.size === 0) setIsAiSpeaking(false);
              };

              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += audioBuffer.duration;
              sourcesRef.current.add(source);
            }

            if (message.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => s.stop());
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
              setIsAiSpeaking(false);
            }
          },
          onerror: (e) => {
            console.error('Gemini error:', e);
            cleanup();
          },
          onclose: () => {
            cleanup();
          }
        }
      });

      sessionRef.current = await sessionPromise;
    } catch (err) {
      console.error('Failed to start recording:', err);
      alert('無法開啟麥克風或連線 API。');
    }
  };

  const renderPhonemeButton = (p: PhonemeInfo) => (
    <button
      key={p.id}
      onClick={() => !isRecording && setSelectedPhoneme(p)}
      disabled={isRecording}
      className={`w-full text-left p-3 rounded-xl border-2 transition-all flex items-center justify-between group ${
        selectedPhoneme.id === p.id 
          ? 'border-orange-500 bg-orange-50 shadow-sm' 
          : 'border-white bg-white/60 hover:border-orange-100'
      } ${isRecording ? 'opacity-50 cursor-not-allowed' : ''}`}
    >
      <div className="flex flex-col">
        <span className="text-xl font-bold text-orange-600">{p.ipa}</span>
        <span className="text-[10px] text-gray-400 font-medium uppercase truncate max-w-[120px]">{p.description}</span>
      </div>
      <div className={`p-1.5 rounded-full ${selectedPhoneme.id === p.id ? 'bg-orange-500 text-white' : 'bg-gray-100 text-gray-300'}`}>
        <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor">
          <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" clipRule="evenodd" />
        </svg>
      </div>
    </button>
  );

  return (
    <div className="min-h-screen flex flex-col bg-orange-50/20">
      <Header progress={progress} />

      <main className="flex-1 max-w-7xl mx-auto w-full p-4 md:p-8 flex flex-col gap-8">
        <div className="flex flex-col md:flex-row justify-between items-center gap-4">
          <div className="text-center md:text-left">
            <h2 className="text-4xl font-black text-gray-800 tracking-tight leading-none mb-2">
              Sound Strong <span className="text-orange-500 underline decoration-orange-200 decoration-4 underline-offset-4">Phonics</span> Coach
            </h2>
            <p className="text-gray-400 font-bold uppercase tracking-widest text-xs">
              赫穠教育文化 · 你的 1 對 1 發音隨身教練
            </p>
          </div>

          <button 
            onClick={() => setShowAchievements(!showAchievements)}
            className={`px-6 py-2.5 rounded-full font-black text-xs uppercase tracking-widest transition-all ${
              showAchievements 
                ? 'bg-orange-500 text-white shadow-orange-200 shadow-xl' 
                : 'bg-white text-gray-400 hover:text-orange-500 border border-orange-100'
            }`}
          >
            {showAchievements ? '返回練習' : '我的成就排行榜'}
          </button>
        </div>

        {showAchievements ? (
          <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
             <GamificationPanel progress={progress} />
          </div>
        ) : (
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 items-start animate-in fade-in duration-500">
            {/* Left: Phoneme Selection */}
            <div className="lg:col-span-4 xl:col-span-3 space-y-6 max-h-[750px] overflow-y-auto pr-2 custom-scrollbar">
              <div>
                <h3 className="text-xs font-black text-gray-400 uppercase tracking-[0.2em] mb-4 flex items-center gap-2">
                  <span className="w-4 h-[2px] bg-orange-300"></span> 子音 Consonants
                </h3>
                <div className="grid grid-cols-1 gap-2">
                  {categorizedPhonemes.consonants.map(renderPhonemeButton)}
                </div>
              </div>

              <div>
                <h3 className="text-xs font-black text-gray-400 uppercase tracking-[0.2em] mb-4 flex items-center gap-2">
                  <span className="w-4 h-[2px] bg-orange-300"></span> 母音 Vowels
                </h3>
                <div className="grid grid-cols-1 gap-2">
                  {categorizedPhonemes.vowels.map(renderPhonemeButton)}
                </div>
              </div>
            </div>

            {/* Right: Main Interface */}
            <div className="lg:col-span-8 xl:col-span-9 space-y-6">
              <div className="bg-white p-6 md:p-10 rounded-[3.5rem] shadow-2xl shadow-orange-100/30 border border-orange-50 relative overflow-hidden">
                <div className="absolute -top-16 -right-16 w-48 h-48 bg-orange-100/30 rounded-full blur-3xl"></div>

                <div className="relative z-10 flex flex-col items-center gap-10">
                  <div className="flex flex-col items-center">
                    <div className="flex items-center gap-4 mb-3">
                      <span className="text-8xl font-black text-orange-500 drop-shadow-sm select-none">{selectedPhoneme.ipa}</span>
                      <div className="h-16 w-[2px] bg-gray-100"></div>
                      <div className="flex flex-col gap-1">
                        <span className="text-lg font-black text-gray-700">{selectedPhoneme.description}</span>
                        <div className="flex gap-2">
                          {selectedPhoneme.exampleWords.map(word => (
                            <span key={word} className="px-4 py-1 bg-orange-50 rounded-xl text-xs font-black text-orange-600 border border-orange-100">{word}</span>
                          ))}
                        </div>
                      </div>
                    </div>
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-10 w-full items-center">
                    <div className="flex flex-col items-center gap-4">
                      <MouthAnimation 
                        state={selectedPhoneme.animationState} 
                        isActive={isAiSpeaking || isRecording} 
                      />
                      <div className="bg-white px-5 py-2 rounded-2xl shadow-sm border border-orange-50 flex items-center gap-3">
                         <span className="w-2.5 h-2.5 rounded-full bg-green-500 animate-pulse"></span>
                         <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Real-time Visual Coach</span>
                      </div>
                    </div>

                    <div className="space-y-6">
                      <div className="bg-orange-50/50 backdrop-blur-sm border border-orange-100 p-8 rounded-[2.5rem] shadow-inner text-center relative min-h-[180px] flex flex-col items-center justify-center transition-all duration-300">
                         {isAiSpeaking && (
                           <div className="absolute -top-3 left-1/2 -translate-x-1/2 flex items-center gap-1.5 bg-white px-4 py-1.5 rounded-full shadow-lg border border-orange-100">
                              {[1,2,3,4,5,6].map(i => (
                                <div key={i} className={`w-1.5 h-4 bg-orange-500 rounded-full animate-bounce`} style={{ animationDelay: `${i * 0.1}s` }}></div>
                              ))}
                           </div>
                         )}
                         <p className="text-gray-800 font-bold text-xl leading-relaxed">
                           {teacherFeedback}
                         </p>
                      </div>

                      <div className="flex flex-col items-center gap-4">
                        <button
                          onClick={toggleRecording}
                          className={`group relative flex items-center justify-center w-24 h-24 rounded-full transition-all duration-500 transform active:scale-90 ${
                            isRecording 
                              ? 'bg-red-500 shadow-red-200 shadow-2xl scale-110' 
                              : 'bg-orange-500 shadow-orange-300 shadow-2xl hover:scale-105'
                          }`}
                        >
                          {isRecording ? (
                            <div className="w-10 h-10 bg-white rounded-2xl animate-pulse"></div>
                          ) : (
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-12 w-12 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
                            </svg>
                          )}
                          <div className={`absolute -inset-3 rounded-full border-4 ${isRecording ? 'border-red-400 animate-ping opacity-20' : 'border-transparent'}`}></div>
                        </button>
                        <p className={`text-[10px] font-black tracking-[0.3em] uppercase ${isRecording ? 'text-red-500 animate-pulse' : 'text-orange-400'}`}>
                          {isRecording ? 'Recording...' : 'Tap to Practice'}
                        </p>
                      </div>
                    </div>
                  </div>

                  <div className="w-full grid grid-cols-1 md:grid-cols-2 gap-6">
                     <div className="bg-white p-6 rounded-[2rem] border border-orange-50 flex items-start gap-4 transition-all hover:border-orange-200">
                        <div className="bg-green-100 text-green-600 p-2.5 rounded-2xl">
                          <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                          </svg>
                        </div>
                        <div>
                          <h4 className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">發音要點 Pro Tips</h4>
                          <p className="text-sm text-gray-700 font-bold leading-relaxed">{selectedPhoneme.tips}</p>
                        </div>
                     </div>
                     <div className="bg-white p-6 rounded-[2rem] border border-orange-50 flex items-start gap-4 transition-all hover:border-orange-200">
                        <div className="bg-red-100 text-red-600 p-2.5 rounded-2xl">
                          <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
                          </svg>
                        </div>
                        <div>
                          <h4 className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">常見錯誤 Warnings</h4>
