        .custom-scrollbar::-webkit-scrollbar-thumb { background: #ffe7d1; border-radius: 10px; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #fb923c; }
        @keyframes fade-in { from { opacity: 0; } to { opacity: 1; } }
        @keyframes slide-in-from-bottom-4 { from { transform: translateY(1rem); } to { transform: translateY(0); } }
        .animate-in { animation: fade-in 0.5s ease-out, slide-in-from-bottom-4 0.5s ease-out; }
      `}} />
    </div>
  );
};

export default App;

export enum PhonemeType {
  CONSONANT = 'CONSONANT',
  VOWEL = 'VOWEL',
}

export enum PracticeMode {
  PHONEME = 'PHONEME',
  MINIMAL_PAIRS = 'MINIMAL_PAIRS',
  SENTENCES = 'SENTENCES',
}

export interface MinimalPair {
  word1: string;
  word2: string;
  targetIpa: string;
  comparisonIpa: string;
}

export interface PhonemeInfo {
  id: string;
  ipa: string;
  exampleWords: string[];
  type: PhonemeType;
  description: string;
  tips: string;
  commonMistakes: string;
  animationState: 'neutral' | 'open' | 'tongue-out' | 'tongue-up' | 'rounded';
  minimalPairs?: MinimalPair[];
  sentences?: string[];
}

export interface TranscriptionItem {
  role: 'user' | 'model';
  text: string;
  timestamp: number;
}

export interface Badge {
  id: string;
  name: string;
  description: string;
  icon: string;
  color: string;
}

export interface UserProgress {
  points: number;
  level: number;
  streak: number;
  lastPracticeDate: string | null;
  badges: string[]; // IDs of earned badges
  sessionsCount: number;
}

export interface LeaderboardEntry {
  name: string;
  points: number;
  isCurrentUser?: boolean;
}

import React, { useState, useCallback, useRef, useMemo, useEffect } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import Header from './components/Header';
import MouthAnimation from './components/MouthAnimation';
import GamificationPanel from './components/GamificationPanel';
import { PHONEMES, TEACHER_SYSTEM_PROMPT } from './constants';
import { PhonemeInfo, TranscriptionItem, PhonemeType, UserProgress, PracticeMode } from './types';
import { encode, decode, decodeAudioData, floatTo16BitPCM } from './services/audioUtils';

const STORAGE_KEY = 'sound_strong_user_progress';

const DEFAULT_PROGRESS: UserProgress = {
  points: 0,
  level: 1,
  streak: 0,
  lastPracticeDate: null,
  badges: [],
  sessionsCount: 0,
};

const App: React.FC = () => {
  const [selectedPhoneme, setSelectedPhoneme] = useState<PhonemeInfo>(PHONEMES[0]);
  const [activeMode, setActiveMode] = useState<PracticeMode>(PracticeMode.PHONEME);
  const [isRecording, setIsRecording] = useState(false);
  const [transcriptions, setTranscriptions] = useState<TranscriptionItem[]>([]);
  const [teacherFeedback, setTeacherFeedback] = useState<string>("老師正在聽你練習喔！準備好了就點擊下方按鈕開始吧。");
  const [isAiSpeaking, setIsAiSpeaking] = useState(false);
  const [showAchievements, setShowAchievements] = useState(false);

  // Gamification State
  const [progress, setProgress] = useState<UserProgress>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : DEFAULT_PROGRESS;
  });

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(progress));
  }, [progress]);

  // Grouping phonemes for better UX
  const categorizedPhonemes = useMemo(() => {
    return {
      consonants: PHONEMES.filter(p => p.type === PhonemeType.CONSONANT),
      vowels: PHONEMES.filter(p => p.type === PhonemeType.VOWEL),
    };
  }, []);

  // Navigation Logic
  const currentIndex = useMemo(() => 
    PHONEMES.findIndex(p => p.id === selectedPhoneme.id),
  [selectedPhoneme]);

  const isLastPhoneme = currentIndex === PHONEMES.length - 1;

  const handleNextPhoneme = useCallback(() => {
    if (!isLastPhoneme && !isRecording) {
      const nextPhoneme = PHONEMES[currentIndex + 1];
      setSelectedPhoneme(nextPhoneme);
      setTeacherFeedback(`切換到下一課：${nextPhoneme.ipa}。準備好就可以點擊錄音鈕練習囉！`);
      setTranscriptions([]); 
    }
  }, [currentIndex, isLastPhoneme, isRecording]);

  // Refs for audio processing
  const audioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const sessionRef = useRef<any>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const scriptProcessorRef = useRef<ScriptProcessorNode | null>(null);

  const cleanup = useCallback(() => {
    if (sessionRef.current) {
      sessionRef.current = null;
    }
    if (scriptProcessorRef.current) {
      scriptProcessorRef.current.disconnect();
      scriptProcessorRef.current = null;
    }
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
    sourcesRef.current.forEach(source => source.stop());
    sourcesRef.current.clear();
    setIsRecording(false);
    setIsAiSpeaking(false);
  }, []);

  const awardPoints = useCallback((amount: number) => {
    setProgress(prev => {
      const multiplier = activeMode === PracticeMode.SENTENCES ? 3 : activeMode === PracticeMode.MINIMAL_PAIRS ? 2 : 1;
      const actualAward = amount * multiplier;
      const newPoints = prev.points + actualAward;
      const newLevel = Math.floor(newPoints / 500) + 1;
      const newBadges = [...prev.badges];

      if (!newBadges.includes('first_step')) newBadges.push('first_step');
      if (actualAward >= 100 && !newBadges.includes('perfect_score')) newBadges.push('perfect_score');

      return {
        ...prev,
        points: newPoints,
        level: newLevel,
        badges: newBadges,
      };
    });
  }, [activeMode]);

  const toggleRecording = async () => {
    if (isRecording) {
      cleanup();
      return;
    }

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

      if (!audioContextRef.current) {
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      }
      if (!outputAudioContextRef.current) {
        outputAudioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      }

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      const modeContext = activeMode === PracticeMode.MINIMAL_PAIRS 
        ? `目前的模式是【最小對立體對比練習】。請特別注意 ${selectedPhoneme.minimalPairs?.[0]?.word1} 與 ${selectedPhoneme.minimalPairs?.[0]?.word2} 之間的差異。`
        : activeMode === PracticeMode.SENTENCES
        ? `目前的模式是【句子應用練習】。請注意句子的流暢度與語調。`
        : `目前的模式是【基礎單字發音】。`;

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          systemInstruction: TEACHER_SYSTEM_PROMPT + 
            `\n${modeContext}\n` +
            `練習主題：${selectedPhoneme.ipa}\n` +
            `發音祕訣：${selectedPhoneme.tips}\n` +
            `常見錯誤：${selectedPhoneme.commonMistakes}`,
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } },
          },
          inputAudioTranscription: {},
          outputAudioTranscription: {},
        },
        callbacks: {
          onopen: () => {
            setIsRecording(true);
            const source = audioContextRef.current!.createMediaStreamSource(stream);
            const scriptProcessor = audioContextRef.current!.createScriptProcessor(4096, 1, 1);
            scriptProcessorRef.current = scriptProcessor;

            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const pcmData = floatTo16BitPCM(inputData);
              const base64Data = encode(pcmData);

              sessionPromise.then(session => {
                session.sendRealtimeInput({
                  media: {
                    data: base64Data,
                    mimeType: 'audio/pcm;rate=16000'
                  }
                });
              });
            };

            source.connect(scriptProcessor);
            scriptProcessor.connect(audioContextRef.current!.destination);

            setProgress(prev => ({
              ...prev,
              sessionsCount: prev.sessionsCount + 1,
              streak: prev.streak + 1
            }));
          },
          onmessage: async (message: LiveServerMessage) => {
            if (message.serverContent?.inputTranscription) {
              const text = message.serverContent.inputTranscription.text;
              setTranscriptions(prev => [...prev, { role: 'user', text, timestamp: Date.now() }]);
            }
            if (message.serverContent?.outputTranscription) {
              const text = message.serverContent.outputTranscription.text;
              setTeacherFeedback(text);
              setTranscriptions(prev => [...prev, { role: 'model', text, timestamp: Date.now() }]);

              if (text.includes('👏') || text.includes('棒') || text.includes('標準')) {
                awardPoints(50);
              } else {
                awardPoints(10);
              }
            }

            const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64Audio) {
              setIsAiSpeaking(true);
              const outCtx = outputAudioContextRef.current!;
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outCtx.currentTime);

              const audioBuffer = await decodeAudioData(decode(base64Audio), outCtx, 24000, 1);
              const source = outCtx.createBufferSource();
              source.buffer = audioBuffer;
              source.connect(outCtx.destination);

              source.onended = () => {
                sourcesRef.current.delete(source);
                if (sourcesRef.current.size === 0) setIsAiSpeaking(false);
              };

              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += audioBuffer.duration;
              sourcesRef.add(source);
            }

            if (message.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => s.stop());
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
              setIsAiSpeaking(false);
            }
          },
          onerror: (e) => {
            console.error('Gemini error:', e);
            cleanup();
          },
          onclose: () => {
            cleanup();
          }
        }
      });

      sessionRef.current = await sessionPromise;
    } catch (err) {
      console.error('Failed to start recording:', err);
      alert('無法開啟麥克風或連線 API。');
    }
  };

  const renderPhonemeButton = (p: PhonemeInfo) => (
    <button
      key={p.id}
      onClick={() => !isRecording && setSelectedPhoneme(p)}
      disabled={isRecording}
      className={`w-full text-left p-3 rounded-xl border-2 transition-all flex items-center justify-between group ${
        selectedPhoneme.id === p.id 
          ? 'border-orange-500 bg-orange-50 shadow-sm' 
          : 'border-white bg-white/60 hover:border-orange-100'
      } ${isRecording ? 'opacity-50 cursor-not-allowed' : ''}`}
    >
      <div className="flex flex-col">
        <span className="text-xl font-bold text-orange-600">{p.ipa}</span>
        <span className="text-[10px] text-gray-400 font-medium uppercase truncate max-w-[120px]">{p.description}</span>
      </div>
    </button>
  );

  return (
    <div className="min-h-screen flex flex-col bg-orange-50/20">
      <Header progress={progress} />

      <main className="flex-1 max-w-7xl mx-auto w-full p-4 md:p-8 flex flex-col gap-8">
        <div className="flex flex-col md:flex-row justify-between items-center gap-4">
          <div className="text-center md:text-left">
            <h2 className="text-4xl font-black text-gray-800 tracking-tight leading-none mb-2">
              Sound Strong <span className="text-orange-500 underline decoration-orange-200 decoration-4 underline-offset-4">Phonics</span> Coach
            </h2>
          </div>

          <button 
            onClick={() => setShowAchievements(!showAchievements)}
            className={`px-6 py-2.5 rounded-full font-black text-xs uppercase tracking-widest transition-all ${
              showAchievements 
                ? 'bg-orange-500 text-white shadow-orange-200 shadow-xl' 
                : 'bg-white text-gray-400 hover:text-orange-500 border border-orange-100'
            }`}
          >
            {showAchievements ? '返回練習' : '我的成就排行榜'}
          </button>
        </div>

        {!showAchievements && (
          <div className="flex justify-center">
            <div className="bg-white/80 backdrop-blur-sm p-1.5 rounded-2xl border border-orange-100 flex gap-1 shadow-sm">
              {[
                { id: PracticeMode.PHONEME, label: '單字基礎', icon: '🔤' },
                { id: PracticeMode.MINIMAL_PAIRS, label: '對比糾錯', icon: '⚖️' },
                { id: PracticeMode.SENTENCES, label: '句子應用', icon: '📝' }
              ].map(mode => (
                <button
                  key={mode.id}
                  onClick={() => !isRecording && setActiveMode(mode.id)}
                  disabled={isRecording}
                  className={`px-6 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all flex items-center gap-2 ${
                    activeMode === mode.id
                      ? 'bg-orange-500 text-white shadow-md'
                      : 'text-gray-400 hover:text-orange-500 hover:bg-orange-50'
                  } ${isRecording ? 'opacity-50' : ''}`}
                >
                  <span>{mode.icon}</span>
                  {mode.label}
                </button>
              ))}
            </div>
          </div>
        )}

        {showAchievements ? (
          <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
             <GamificationPanel progress={progress} />
          </div>
        ) : (
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 items-start animate-in fade-in duration-500">
            {/* Left: Phoneme Selection */}
            <div className="lg:col-span-4 xl:col-span-3 space-y-6 max-h-[750px] overflow-y-auto pr-2 custom-scrollbar">
              <div>
                <h3 className="text-xs font-black text-gray-400 uppercase tracking-[0.2em] mb-4 flex items-center gap-2">
                  <span className="w-4 h-[2px] bg-orange-300"></span> 課程目錄 Lessons
                </h3>
                <div className="grid grid-cols-1 gap-2">
                  {categorizedPhonemes.consonants.map(renderPhonemeButton)}
                  {categorizedPhonemes.vowels.map(renderPhonemeButton)}
                </div>
              </div>
            </div>

            {/* Right: Main Interface */}
            <div className="lg:col-span-8 xl:col-span-9 space-y-6">
              <div className="bg-white p-6 md:p-10 rounded-[3.5rem] shadow-2xl shadow-orange-100/30 border border-orange-50 relative overflow-hidden">
                <div className="relative z-10 flex flex-col items-center gap-10">
                  <div className="flex flex-col items-center w-full">
                    <div className="flex items-center gap-4 mb-6">
                      <span className="text-8xl font-black text-orange-500 drop-shadow-sm">{selectedPhoneme.ipa}</span>
                      <div className="h-16 w-[2px] bg-gray-100"></div>
                      <span className="text-lg font-black text-gray-700">{selectedPhoneme.description}</span>
                    </div>

                    {/* Dynamic Content Based on Mode */}
                    <div className="w-full animate-in fade-in zoom-in duration-300">
                      {activeMode === PracticeMode.PHONEME && (
                        <div className="flex justify-center gap-2">
                          {selectedPhoneme.exampleWords.map(word => (
                            <span key={word} className="px-6 py-2 bg-orange-50 rounded-2xl text-lg font-black text-orange-600 border border-orange-100 shadow-sm">{word}</span>
                          ))}
                        </div>
                      )}

                      {activeMode === PracticeMode.MINIMAL_PAIRS && (
                        <div className="grid grid-cols-2 gap-4">
                          {selectedPhoneme.minimalPairs?.map((pair, idx) => (
                            <div key={idx} className="bg-orange-50/50 p-6 rounded-[2.5rem] border border-orange-100 flex flex-col items-center gap-2">
                               <div className="flex items-center gap-4 w-full justify-center">
                                 <div className="flex flex-col items-center">
                                   <span className="text-2xl font-black text-gray-800">{pair.word1}</span>
                                   <span className="text-xs font-bold text-orange-400">{pair.targetIpa}</span>
                                 </div>
                                 <span className="text-gray-300 font-bold italic">vs</span>
                                 <div className="flex flex-col items-center">
                                   <span className="text-2xl font-black text-gray-400">{pair.word2}</span>
                                   <span className="text-xs font-bold text-gray-300">{pair.comparisonIpa}</span>
                                 </div>
                               </div>
                            </div>
                          ))}
                        </div>
                      )}

                      {activeMode === PracticeMode.SENTENCES && (
                        <div className="space-y-3">
                          {selectedPhoneme.sentences?.map((sentence, idx) => (
                            <div key={idx} className="bg-white p-5 rounded-[2rem] border-2 border-orange-50 shadow-sm text-center">
                              <p className="text-xl font-bold text-gray-700 leading-relaxed italic">"{sentence}"</p>
                            </div>
                          ))}
                        </div>
                      )}
                    </div>
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-10 w-full items-center">
                    <div className="flex flex-col items-center gap-4">
                      <MouthAnimation 
                        state={selectedPhoneme.animationState} 
                        isActive={isAiSpeaking || isRecording} 
                      />
                    </div>

                    <div className="space-y-6">
                      <div className="bg-orange-50/50 backdrop-blur-sm border border-orange-100 p-8 rounded-[2.5rem] shadow-inner text-center relative min-h-[180px] flex flex-col items-center justify-center transition-all duration-300">
                         {isAiSpeaking && (
                           <div className="absolute -top-3 left-1/2 -translate-x-1/2 flex items-center gap-1.5 bg-white px-4 py-1.5 rounded-full shadow-lg border border-orange-100">
                              {[1,2,3,4,5,6].map(i => (
                                <div key={i} className={`w-1.5 h-4 bg-orange-500 rounded-full animate-bounce`} style={{ animationDelay: `${i * 0.1}s` }}></div>
                              ))}
                           </div>
                         )}
                         <p className="text-gray-800 font-bold text-xl leading-relaxed">
                           {teacherFeedback}
                         </p>
                      </div>

                      <div className="flex flex-col items-center gap-6">
                        <div className="flex items-center gap-6">
                           <button
                            onClick={toggleRecording}
                            className={`group relative flex items-center justify-center w-24 h-24 rounded-full transition-all duration-500 transform active:scale-90 ${
                              isRecording ? 'bg-red-500 shadow-red-200 shadow-2xl scale-110' : 'bg-orange-500 shadow-orange-300 shadow-2xl hover:scale-105'
                            }`}
                          >
                            {isRecording ? <div className="w-10 h-10 bg-white rounded-2xl animate-pulse"></div> : <svg xmlns="http://www.w3.org/2000/svg" className="h-12 w-12 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" /></svg>}
                            <div className={`absolute -inset-3 rounded-full border-4 ${isRecording ? 'border-red-400 animate-ping opacity-20' : 'border-transparent'}`}></div>
                          </button>

                          <button
                            onClick={handleNextPhoneme}
                            disabled={isLastPhoneme || isRecording}
                            className={`flex flex-col items-center justify-center w-20 h-20 rounded-full transition-all border-2 ${
                              isLastPhoneme || isRecording ? 'border-gray-100 bg-gray-50 text-gray-300' : 'border-orange-200 bg-white text-orange-500 hover:border-orange-500 hover:bg-orange-50 shadow-sm'
                            }`}
                          >
                             <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M13 5l7 7-7 7M5 5l7 7-7 7" /></svg>
                             <span className="text-[8px] font-black uppercase mt-1">Next</span>
                          </button>
                        </div>
                        <p className={`text-[10px] font-black tracking-[0.3em] uppercase ${isRecording ? 'text-red-500 animate-pulse' : 'text-orange-400'}`}>
                          {isRecording ? 'Recording...' : 'Tap to Practice'}
                        </p>
                      </div>
                    </div>
                  </div>
                </div>
              </div>

              {/* History Section */}
              <div className="bg-white p-8 rounded-[2.5rem] border border-orange-50 max-h-72 overflow-y-auto custom-scrollbar shadow-sm shadow-orange-50">
                <h4 className="text-[10px] font-black text-gray-400 uppercase tracking-[0.4em] mb-6 flex justify-center">Session History</h4>
                <div className="space-y-4">
                  {transcriptions.length === 0 ? <p className="text-sm text-gray-400 font-medium italic text-center py-6">準備好就點擊錄音鍵開始練習喔！老師在等你。</p> : 
                    transcriptions.map((item, idx) => (
                      <div key={idx} className={`flex ${item.role === 'model' ? 'justify-start' : 'justify-end'}`}>
                        <div className={`max-w-[85%] p-5 rounded-3xl text-sm shadow-sm transition-all hover:shadow-md ${
                          item.role === 'model' ? 'bg-white text-gray-700 rounded-tl-none border border-orange-100 font-medium' : 'bg-gradient-to-br from-orange-400 to-orange-600 text-white rounded-tr-none font-black shadow-orange-100'
                        }`}>{item.text}</div>
                      </div>
                    ))
                  }
                </div>
              </div>
            </div>
          </div>
        )}
      </main>

      <style dangerouslySetInnerHTML={{ __html: `
        .custom-scrollbar::-webkit-scrollbar { width: 5px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: #fffcf9; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #ffe7d1; border-radius: 10px; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #fb923c; }
        @keyframes fade-in { from { opacity: 0; } to { opacity: 1; } }
        @keyframes slide-in-from-bottom-4 { from { transform: translateY(1rem); } to { transform: translateY(0); } }
        @keyframes zoom-in { from { opacity: 0; transform: scale(0.95); } to { opacity: 1; transform: scale(1); } }
        .animate-in { animation: fade-in 0.5s ease-out, slide-in-from-bottom-4 0.5s ease-out; }
      `}} />
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { UserProgress } from '../types';

interface HeaderProps {
  progress?: UserProgress;
}

const Header: React.FC<HeaderProps> = ({ progress }) => {
  const [showLevelUp, setShowLevelUp] = useState(false);
  const prevLevelRef = useRef<number | undefined>(progress?.level);

  useEffect(() => {
    if (progress?.level && prevLevelRef.current && progress.level > prevLevelRef.current) {
      setShowLevelUp(true);
      const timer = setTimeout(() => setShowLevelUp(false), 3000);
      prevLevelRef.current = progress.level;
      return () => clearTimeout(timer);
    }
    prevLevelRef.current = progress?.level;
  }, [progress?.level]);

  return (
    <header className="bg-white border-b border-orange-100 py-3 px-6 sticky top-0 z-50 shadow-sm backdrop-blur-md bg-white/90">
      <div className="max-w-6xl mx-auto flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="bg-orange-500 text-white p-2 rounded-xl shadow-orange-200 shadow-lg">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
            </svg>
          </div>
          <div className="hidden sm:block">
            <h1 className="text-lg font-black text-gray-800 tracking-tight leading-none mb-0.5">Sound Strong AI</h1>
            <p className="text-[10px] text-orange-600 font-black uppercase tracking-widest">Education Coach</p>
          </div>
        </div>

        {progress && (
          <div className="flex items-center gap-4 md:gap-8 relative">
            <div className="flex items-center gap-2 group cursor-pointer">
              <div className="bg-orange-100 text-orange-600 p-1.5 rounded-lg group-hover:bg-orange-200 transition-colors">
                 🔥
              </div>
              <div className="flex flex-col">
                <span className="text-xs font-black text-orange-600 leading-none">{progress.streak}</span>
                <span className="text-[9px] font-bold text-gray-400 uppercase">Streak</span>
              </div>
            </div>

            <div className="flex items-center gap-2 group cursor-pointer">
              <div className="bg-yellow-100 text-yellow-600 p-1.5 rounded-lg group-hover:bg-yellow-200 transition-colors">
                 ⭐
              </div>
              <div className="flex flex-col">
                <span className="text-xs font-black text-gray-700 leading-none">{progress.points}</span>
                <span className="text-[9px] font-bold text-gray-400 uppercase">Points</span>
              </div>
            </div>

            <div className="hidden md:flex items-center gap-2 group cursor-pointer border-l border-orange-100 pl-8 relative">
              <div className={`w-8 h-8 rounded-full bg-gradient-to-br from-orange-400 to-orange-600 flex items-center justify-center text-white text-[10px] font-black shadow-md transition-all duration-500 ${showLevelUp ? 'scale-125 ring-4 ring-orange-200 animate-bounce' : ''}`}>
                 L{progress.level}
              </div>
              <div className="flex flex-col">
                <span className="text-xs font-black text-gray-700 leading-none">Level Up</span>
                <div className="w-16 h-1 bg-gray-100 rounded-full mt-1 overflow-hidden">
                  <div 
                    className={`h-full bg-orange-400 transition-all duration-1000 ${showLevelUp ? 'w-full' : ''}`} 
                    style={{ width: showLevelUp ? '100%' : `${(progress.points % 500) / 5}%` }}
                  ></div>
                </div>
              </div>

              {/* Level Up Popover */}
              {showLevelUp && (
                <div className="absolute -top-12 left-1/2 -translate-x-1/2 animate-level-up-pop pointer-events-none">
                  <div className="bg-gradient-to-r from-yellow-400 to-orange-500 text-white text-[10px] font-black px-3 py-1 rounded-full shadow-lg whitespace-nowrap border-2 border-white">
                    LEVEL UP! 🎊
                  </div>
                </div>
              )}
            </div>
          </div>
        )}

        <nav className="hidden lg:flex gap-6 text-xs font-black text-gray-400 uppercase tracking-widest">
          <a href="#" className="hover:text-orange-500 transition-colors">Course</a>
          <a href="#" className="hover:text-orange-500 transition-colors">History</a>
        </nav>
      </div>

      <style dangerouslySetInnerHTML={{ __html: `
        @keyframes level-up-pop {
          0% { transform: translate(-50%, 20px) scale(0); opacity: 0; }
          20% { transform: translate(-50%, 0) scale(1.2); opacity: 1; }
          40% { transform: translate(-50%, -5px) scale(1); opacity: 1; }
          80% { transform: translate(-50%, -10px) scale(1); opacity: 1; }
          100% { transform: translate(-50%, -20px) scale(0.8); opacity: 0; }
        }
        .animate-level-up-pop {
          animation: level-up-pop 3s ease-out forwards;
        }
      `}} />
    </header>
  );
};

export default Header;

import React, { useState, useCallback, useRef, useMemo, useEffect } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import Header from './components/Header';
import MouthAnimation from './components/MouthAnimation';
import GamificationPanel from './components/GamificationPanel';
import { PHONEMES, TEACHER_SYSTEM_PROMPT } from './constants';
import { PhonemeInfo, TranscriptionItem, PhonemeType, UserProgress, PracticeMode } from './types';
import { encode, decode, decodeAudioData, floatTo16BitPCM } from './services/audioUtils';

const STORAGE_KEY = 'sound_strong_user_progress';

const DEFAULT_PROGRESS: UserProgress = {
  points: 0,
  level: 1,
  streak: 0,
  lastPracticeDate: null,
  badges: [],
  sessionsCount: 0,
};

const App: React.FC = () => {
  const [selectedPhoneme, setSelectedPhoneme] = useState<PhonemeInfo>(PHONEMES[0]);
  const [activeMode, setActiveMode] = useState<PracticeMode>(PracticeMode.PHONEME);
  const [isRecording, setIsRecording] = useState(false);
  const [transcriptions, setTranscriptions] = useState<TranscriptionItem[]>([]);
  const [teacherFeedback, setTeacherFeedback] = useState<string>("老師正在聽你練習喔！準備好了就點擊下方按鈕開始吧。");
  const [isAiSpeaking, setIsAiSpeaking] = useState(false);
  const [showAchievements, setShowAchievements] = useState(false);

  // Gamification State
  const [progress, setProgress] = useState<UserProgress>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : DEFAULT_PROGRESS;
  });

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(progress));
  }, [progress]);

  // Grouping phonemes for better UX
  const categorizedPhonemes = useMemo(() => {
    return {
      consonants: PHONEMES.filter(p => p.type === PhonemeType.CONSONANT),
      vowels: PHONEMES.filter(p => p.type === PhonemeType.VOWEL),
    };
  }, []);

  // Navigation Logic
  const currentIndex = useMemo(() => 
    PHONEMES.findIndex(p => p.id === selectedPhoneme.id),
  [selectedPhoneme]);

  const isLastPhoneme = currentIndex === PHONEMES.length - 1;

  const handleNextPhoneme = useCallback(() => {
    if (!isLastPhoneme && !isRecording) {
      const nextPhoneme = PHONEMES[currentIndex + 1];
      setSelectedPhoneme(nextPhoneme);
      setTeacherFeedback(`切換到下一課：${nextPhoneme.ipa}。準備好就可以點擊錄音鈕練習囉！`);
      setTranscriptions([]); 
    }
  }, [currentIndex, isLastPhoneme, isRecording]);

  // Refs for audio processing
  const audioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const sessionRef = useRef<any>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const scriptProcessorRef = useRef<ScriptProcessorNode | null>(null);

  const cleanup = useCallback(() => {
    if (sessionRef.current) {
      sessionRef.current = null;
    }
    if (scriptProcessorRef.current) {
      scriptProcessorRef.current.disconnect();
      scriptProcessorRef.current = null;
    }
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
    sourcesRef.current.forEach(source => source.stop());
    sourcesRef.current.clear();
    setIsRecording(false);
    setIsAiSpeaking(false);
  }, []);

  const awardPoints = useCallback((amount: number) => {
    setProgress(prev => {
      const multiplier = activeMode === PracticeMode.SENTENCES ? 3 : activeMode === PracticeMode.MINIMAL_PAIRS ? 2 : 1;
      const actualAward = amount * multiplier;
      const newPoints = prev.points + actualAward;
      const newLevel = Math.floor(newPoints / 500) + 1;
      const newBadges = [...prev.badges];

      if (!newBadges.includes('first_step')) newBadges.push('first_step');
      if (actualAward >= 100 && !newBadges.includes('perfect_score')) newBadges.push('perfect_score');

      return {
        ...prev,
        points: newPoints,
        level: newLevel,
        badges: newBadges,
      };
    });
  }, [activeMode]);

  const toggleRecording = async () => {
    if (isRecording) {
      cleanup();
      return;
    }

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

      if (!audioContextRef.current) {
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      }
      if (!outputAudioContextRef.current) {
        outputAudioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      }

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      const modeContext = activeMode === PracticeMode.MINIMAL_PAIRS 
        ? `目前的模式是【最小對立體對比練習】。請特別注意 ${selectedPhoneme.minimalPairs?.[0]?.word1} 與 ${selectedPhoneme.minimalPairs?.[0]?.word2} 之間的差異。`
        : activeMode === PracticeMode.SENTENCES
        ? `目前的模式是【句子應用練習】。請注意句子的流暢度與語調。`
        : `目前的模式是【基礎單字發音】。`;

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          systemInstruction: TEACHER_SYSTEM_PROMPT + 
            `\n${modeContext}\n` +
            `練習主題：${selectedPhoneme.ipa}\n` +
            `發音祕訣：${selectedPhoneme.tips}\n` +
            `常見錯誤：${selectedPhoneme.commonMistakes}`,
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } },
          },
          inputAudioTranscription: {},
          outputAudioTranscription: {},
        },
        callbacks: {
          onopen: () => {
            setIsRecording(true);
            const source = audioContextRef.current!.createMediaStreamSource(stream);
            const scriptProcessor = audioContextRef.current!.createScriptProcessor(4096, 1, 1);
            scriptProcessorRef.current = scriptProcessor;

            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const pcmData = floatTo16BitPCM(inputData);
              const base64Data = encode(pcmData);

              sessionPromise.then(session => {
                session.sendRealtimeInput({
                  media: {
                    data: base64Data,
                    mimeType: 'audio/pcm;rate=16000'
                  }
                });
              });
            };

            source.connect(scriptProcessor);
            scriptProcessor.connect(audioContextRef.current!.destination);

            setProgress(prev => ({
              ...prev,
              sessionsCount: prev.sessionsCount + 1,
              streak: prev.streak + 1
            }));
          },
          onmessage: async (message: LiveServerMessage) => {
            if (message.serverContent?.inputTranscription) {
              const text = message.serverContent.inputTranscription.text;
              setTranscriptions(prev => [...prev, { role: 'user', text, timestamp: Date.now() }]);
            }
            if (message.serverContent?.outputTranscription) {
              const text = message.serverContent.outputTranscription.text;
              setTeacherFeedback(text);
              setTranscriptions(prev => [...prev, { role: 'model', text, timestamp: Date.now() }]);

              if (text.includes('👏') || text.includes('棒') || text.includes('標準')) {
                awardPoints(50);
              } else {
                awardPoints(10);
              }
            }

            const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64Audio) {
              setIsAiSpeaking(true);
              const outCtx = outputAudioContextRef.current!;
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outCtx.currentTime);

              const audioBuffer = await decodeAudioData(decode(base64Audio), outCtx, 24000, 1);
              const source = outCtx.createBufferSource();
              source.buffer = audioBuffer;
              source.connect(outCtx.destination);

              source.onended = () => {
                sourcesRef.current.delete(source);
                if (sourcesRef.current.size === 0) setIsAiSpeaking(false);
              };

              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += audioBuffer.duration;
              sourcesRef.current.add(source);
            }

            if (message.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => s.stop());
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
              setIsAiSpeaking(false);
            }
          },
          onerror: (e) => {
            console.error('Gemini error:', e);
            cleanup();
          },
          onclose: () => {
            cleanup();
          }
        }
      });

      sessionRef.current = await sessionPromise;
    } catch (err) {
      console.error('Failed to start recording:', err);
      alert('無法開啟麥克風或連線 API。');
    }
  };

  const renderPhonemeButton = (p: PhonemeInfo) => (
    <button
      key={p.id}
      onClick={() => !isRecording && setSelectedPhoneme(p)}
      disabled={isRecording}
      className={`w-full text-left p-3 rounded-xl border-2 transition-all flex items-center justify-between group ${
        selectedPhoneme.id === p.id 
          ? 'border-orange-500 bg-orange-50 shadow-sm' 
          : 'border-white bg-white/60 hover:border-orange-100'
      } ${isRecording ? 'opacity-50 cursor-not-allowed' : ''}`}
    >
      <div className="flex flex-col">
        <span className="text-xl font-bold text-orange-600">{p.ipa}</span>
        <span className="text-[10px] text-gray-400 font-medium uppercase truncate max-w-[120px]">{p.description}</span>
      </div>
    </button>
  );

  return (
    <div className="min-h-screen flex flex-col bg-orange-50/20">
      <Header progress={progress} />

      <main className="flex-1 max-w-7xl mx-auto w-full p-4 md:p-8 flex flex-col gap-8">
        <div className="flex flex-col md:flex-row justify-between items-center gap-4">
          <div className="text-center md:text-left">
            <h2 className="text-4xl font-black text-gray-800 tracking-tight leading-none mb-2">
              Sound Strong <span className="text-orange-500 underline decoration-orange-200 decoration-4 underline-offset-4">Phonics</span> Coach
            </h2>
          </div>

          <button 
            onClick={() => setShowAchievements(!showAchievements)}
            className={`px-6 py-2.5 rounded-full font-black text-xs uppercase tracking-widest transition-all ${
              showAchievements 
                ? 'bg-orange-500 text-white shadow-orange-200 shadow-xl' 
                : 'bg-white text-gray-400 hover:text-orange-500 border border-orange-100'
            }`}
          >
            {showAchievements ? '返回練習' : '我的成就排行榜'}
          </button>
        </div>

        {!showAchievements && (
          <div className="flex justify-center">
            <div className="bg-white/80 backdrop-blur-sm p-1.5 rounded-2xl border border-orange-100 flex gap-1 shadow-sm">
              {[
                { id: PracticeMode.PHONEME, label: '單字基礎', icon: '🔤' },
                { id: PracticeMode.MINIMAL_PAIRS, label: '對比糾錯', icon: '⚖️' },
                { id: PracticeMode.SENTENCES, label: '句子應用', icon: '📝' }
              ].map(mode => (
                <button
                  key={mode.id}
                  onClick={() => !isRecording && setActiveMode(mode.id)}
                  disabled={isRecording}
                  className={`px-6 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all flex items-center gap-2 ${
                    activeMode === mode.id
                      ? 'bg-orange-500 text-white shadow-md'
                      : 'text-gray-400 hover:text-orange-500 hover:bg-orange-50'
                  } ${isRecording ? 'opacity-50' : ''}`}
                >
                  <span>{mode.icon}</span>
                  {mode.label}
                </button>
              ))}
            </div>
          </div>
        )}

        {showAchievements ? (
          <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
             <GamificationPanel progress={progress} />
          </div>
        ) : (
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 items-start animate-in fade-in duration-500">
            {/* Left: Phoneme Selection */}
            <div className="lg:col-span-4 xl:col-span-3 space-y-6 max-h-[750px] overflow-y-auto pr-2 custom-scrollbar">
              <div>
                <h3 className="text-xs font-black text-gray-400 uppercase tracking-[0.2em] mb-4 flex items-center gap-2">
                  <span className="w-4 h-[2px] bg-orange-300"></span> 課程目錄 Lessons
                </h3>
                <div className="grid grid-cols-1 gap-2">
                  {categorizedPhonemes.consonants.map(renderPhonemeButton)}
                  {categorizedPhonemes.vowels.map(renderPhonemeButton)}
                </div>
              </div>
            </div>

            {/* Right: Main Interface */}
            <div className="lg:col-span-8 xl:col-span-9 space-y-6">
              <div className="bg-white p-6 md:p-10 rounded-[3.5rem] shadow-2xl shadow-orange-100/30 border border-orange-50 relative overflow-hidden">
                <div className="relative z-10 flex flex-col items-center gap-10">
                  <div className="flex flex-col items-center w-full">
                    <div className="flex items-center gap-4 mb-6">
                      <span className="text-8xl font-black text-orange-500 drop-shadow-sm">{selectedPhoneme.ipa}</span>
                      <div className="h-16 w-[2px] bg-gray-100"></div>
                      <span className="text-lg font-black text-gray-700">{selectedPhoneme.description}</span>
                    </div>

                    {/* Dynamic Content Based on Mode */}
                    <div className="w-full animate-in fade-in zoom-in duration-300">
                      {activeMode === PracticeMode.PHONEME && (
                        <div className="flex justify-center gap-2">
                          {selectedPhoneme.exampleWords.map(word => (
                            <span key={word} className="px-6 py-2 bg-orange-50 rounded-2xl text-lg font-black text-orange-600 border border-orange-100 shadow-sm">{word}</span>
                          ))}
                        </div>
                      )}

                      {activeMode === PracticeMode.MINIMAL_PAIRS && (
                        <div className="grid grid-cols-2 gap-4">
                          {selectedPhoneme.minimalPairs?.map((pair, idx) => (
                            <div key={idx} className="bg-orange-50/50 p-6 rounded-[2.5rem] border border-orange-100 flex flex-col items-center gap-2">
                               <div className="flex items-center gap-4 w-full justify-center">
                                 <div className="flex flex-col items-center">
                                   <span className="text-2xl font-black text-gray-800">{pair.word1}</span>
                                   <span className="text-xs font-bold text-orange-400">{pair.targetIpa}</span>
                                 </div>
                                 <span className="text-gray-300 font-bold italic">vs</span>
                                 <div className="flex flex-col items-center">
                                   <span className="text-2xl font-black text-gray-400">{pair.word2}</span>
                                   <span className="text-xs font-bold text-gray-300">{pair.comparisonIpa}</span>
                                 </div>
                               </div>
                            </div>
                          ))}
                        </div>
                      )}

                      {activeMode === PracticeMode.SENTENCES && (
                        <div className="space-y-3">
                          {selectedPhoneme.sentences?.map((sentence, idx) => (
                            <div key={idx} className="bg-white p-5 rounded-[2rem] border-2 border-orange-50 shadow-sm text-center">
                              <p className="text-xl font-bold text-gray-700 leading-relaxed italic">"{sentence}"</p>
                            </div>
                          ))}
                        </div>
                      )}
                    </div>
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-10 w-full items-center">
                    <div className="flex flex-col items-center gap-4">
                      <MouthAnimation 
                        state={selectedPhoneme.animationState} 
                        isActive={isAiSpeaking || isRecording} 
                      />
                    </div>

                    <div className="space-y-6">
                      <div className="bg-orange-50/50 backdrop-blur-sm border border-orange-100 p-8 rounded-[2.5rem] shadow-inner text-center relative min-h-[180px] flex flex-col items-center justify-center transition-all duration-300">
                         {isAiSpeaking && (
                           <div className="absolute -top-3 left-1/2 -translate-x-1/2 flex items-center gap-1.5 bg-white px-4 py-1.5 rounded-full shadow-lg border border-orange-100">
                              {[1,2,3,4,5,6].map(i => (
                                <div key={i} className={`w-1.5 h-4 bg-orange-500 rounded-full animate-bounce`} style={{ animationDelay: `${i * 0.1}s` }}></div>
                              ))}
                           </div>
                         )}
                         <p className="text-gray-800 font-bold text-xl leading-relaxed">
                           {teacherFeedback}
                         </p>
                      </div>

                      <div className="flex flex-col items-center gap-6">
                        <div className="flex items-center gap-6">
                           <button
                            onClick={toggleRecording}
                            className={`group relative flex items-center justify-center w-24 h-24 rounded-full transition-all duration-500 transform active:scale-90 ${
                              isRecording ? 'bg-red-500 shadow-red-200 shadow-2xl scale-110' : 'bg-orange-500 shadow-orange-300 shadow-2xl hover:scale-105'
                            }`}
                          >
                            {isRecording ? <div className="w-10 h-10 bg-white rounded-2xl animate-pulse"></div> : <svg xmlns="http://www.w3.org/2000/svg" className="h-12 w-12 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" /></svg>}
                            <div className={`absolute -inset-3 rounded-full border-4 ${isRecording ? 'border-red-400 animate-ping opacity-20' : 'border-transparent'}`}></div>
                          </button>

                          <button
                            onClick={handleNextPhoneme}
                            disabled={isLastPhoneme || isRecording}
                            className={`flex flex-col items-center justify-center w-20 h-20 rounded-full transition-all border-2 ${
                              isLastPhoneme || isRecording ? 'border-gray-100 bg-gray-50 text-gray-300' : 'border-orange-200 bg-white text-orange-500 hover:border-orange-500 hover:bg-orange-50 shadow-sm'
                            }`}
                          >
                             <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M13 5l7 7-7 7M5 5l7 7-7 7" /></svg>
                             <span className="text-[8px] font-black uppercase mt-1">Next</span>
                          </button>
                        </div>
                        <p className={`text-[10px] font-black tracking-[0.3em] uppercase ${isRecording ? 'text-red-500 animate-pulse' : 'text-orange-400'}`}>
                          {isRecording ? 'Recording...' : 'Tap to Practice'}
                        </p>
                      </div>
                    </div>
                  </div>
                </div>
              </div>

              {/* History Section */}
              <div className="bg-white p-8 rounded-[2.5rem] border border-orange-50 max-h-72 overflow-y-auto custom-scrollbar shadow-sm shadow-orange-50">
                <h4 className="text-[10px] font-black text-gray-400 uppercase tracking-[0.4em] mb-6 flex justify-center">Session History</h4>
                <div className="space-y-4">
                  {transcriptions.length === 0 ? <p className="text-sm text-gray-400 font-medium italic text-center py-6">準備好就點擊錄音鍵開始練習喔！老師在等你。</p> : 
                    transcriptions.map((item, idx) => (
                      <div key={idx} className={`flex ${item.role === 'model' ? 'justify-start' : 'justify-end'}`}>
                        <div className={`max-w-[85%] p-5 rounded-3xl text-sm shadow-sm transition-all hover:shadow-md ${
                          item.role === 'model' ? 'bg-white text-gray-700 rounded-tl-none border border-orange-100 font-medium' : 'bg-gradient-to-br from-orange-400 to-orange-600 text-white rounded-tr-none font-black shadow-orange-100'
                        }`}>{item.text}</div>
                      </div>
                    ))
                  }
                </div>
              </div>
            </div>
          </div>
        )}
      </main>

      <style dangerouslySetInnerHTML={{ __html: `
        .custom-scrollbar::-webkit-scrollbar { width: 5px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: #fffcf9; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #ffe7d1; border-radius: 10px; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #fb923c; }
        @keyframes fade-in { from { opacity: 0; } to { opacity: 1; } }
        @keyframes slide-in-from-bottom-4 { from { transform: translateY(1rem); } to { transform: translateY(0); } }
        @keyframes zoom-in { from { opacity: 0; transform: scale(0.95); } to { opacity: 1; transform: scale(1); } }
        .animate-in { animation: fade-in 0.5s ease-out, slide-in-from-bottom-4 0.5s ease-out; }
      `}} />
    </div>
  );
};

export default App;

import React, { useState, useCallback, useRef, useMemo, useEffect } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import Header from './components/Header';
import MouthAnimation from './components/MouthAnimation';
import GamificationPanel from './components/GamificationPanel';
import { PHONEMES, TEACHER_SYSTEM_PROMPT } from './constants';
import { PhonemeInfo, TranscriptionItem, PhonemeType, UserProgress, PracticeMode } from './types';
import { encode, decode, decodeAudioData, floatTo16BitPCM } from './services/audioUtils';

const STORAGE_KEY = 'sound_strong_user_progress';

const DEFAULT_PROGRESS: UserProgress = {
  points: 0,
  level: 1,
  streak: 0,
  lastPracticeDate: null,
  badges: [],
  sessionsCount: 0,
};

const App: React.FC = () => {
  const [selectedPhoneme, setSelectedPhoneme] = useState<PhonemeInfo>(PHONEMES[0]);
  const [activeMode, setActiveMode] = useState<PracticeMode>(PracticeMode.PHONEME);
  const [isRecording, setIsRecording] = useState(false);
  const [transcriptions, setTranscriptions] = useState<TranscriptionItem[]>([]);
  const [teacherFeedback, setTeacherFeedback] = useState<string>("老師正在聽你練習喔！準備好了就點擊下方按鈕開始吧。");
  const [isAiSpeaking, setIsAiSpeaking] = useState(false);
  const [showAchievements, setShowAchievements] = useState(false);

  // Gamification State
  const [progress, setProgress] = useState<UserProgress>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : DEFAULT_PROGRESS;
  });

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(progress));
  }, [progress]);

  // Grouping phonemes for better UX
  const categorizedPhonemes = useMemo(() => {
    return {
      consonants: PHONEMES.filter(p => p.type === PhonemeType.CONSONANT),
      vowels: PHONEMES.filter(p => p.type === PhonemeType.VOWEL),
    };
  }, []);

  // Navigation Logic
  const currentIndex = useMemo(() => 
    PHONEMES.findIndex(p => p.id === selectedPhoneme.id),
  [selectedPhoneme]);

  const isLastPhoneme = currentIndex === PHONEMES.length - 1;

  const handleNextPhoneme = useCallback(() => {
    if (!isLastPhoneme && !isRecording) {
      const nextPhoneme = PHONEMES[currentIndex + 1];
      setSelectedPhoneme(nextPhoneme);
      setTeacherFeedback(`切換到下一課：${nextPhoneme.ipa}。準備好就可以點擊錄音鈕練習囉！`);
      setTranscriptions([]); 
    }
  }, [currentIndex, isLastPhoneme, isRecording]);

  // Refs for audio processing
  const audioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const sessionRef = useRef<any>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const scriptProcessorRef = useRef<ScriptProcessorNode | null>(null);

  const cleanup = useCallback(() => {
    if (sessionRef.current) {
      sessionRef.current = null;
    }
    if (scriptProcessorRef.current) {
      scriptProcessorRef.current.disconnect();
      scriptProcessorRef.current = null;
    }
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
    sourcesRef.current.forEach(source => source.stop());
    sourcesRef.current.clear();
    setIsRecording(false);
    setIsAiSpeaking(false);
  }, []);

  const awardPoints = useCallback((amount: number) => {
    setProgress(prev => {
      const multiplier = activeMode === PracticeMode.SENTENCES ? 3 : activeMode === PracticeMode.MINIMAL_PAIRS ? 2 : 1;
      const actualAward = amount * multiplier;
      const newPoints = prev.points + actualAward;
      const newLevel = Math.floor(newPoints / 500) + 1;
      const newBadges = [...prev.badges];

      if (!newBadges.includes('first_step')) newBadges.push('first_step');
      if (actualAward >= 100 && !newBadges.includes('perfect_score')) newBadges.push('perfect_score');

      return {
        ...prev,
        points: newPoints,
        level: newLevel,
        badges: newBadges,
      };
    });
  }, [activeMode]);

  const toggleRecording = async () => {
    if (isRecording) {
      cleanup();
      return;
    }

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

      if (!audioContextRef.current) {
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      }
      if (!outputAudioContextRef.current) {
        outputAudioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      }

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      const modeContext = activeMode === PracticeMode.MINIMAL_PAIRS 
        ? `目前的模式是【最小對立體對比練習】。請特別注意 ${selectedPhoneme.minimalPairs?.[0]?.word1} 與 ${selectedPhoneme.minimalPairs?.[0]?.word2} 之間的差異。`
        : activeMode === PracticeMode.SENTENCES
        ? `目前的模式是【句子應用練習】。請注意句子的流暢度與語調。`
        : `目前的模式是【基礎單字發音】。`;

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          systemInstruction: TEACHER_SYSTEM_PROMPT + 
            `\n${modeContext}\n` +
            `練習主題：${selectedPhoneme.ipa}\n` +
            `發音祕訣：${selectedPhoneme.tips}\n` +
            `常見錯誤：${selectedPhoneme.commonMistakes}`,
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } },
          },
          inputAudioTranscription: {},
          outputAudioTranscription: {},
        },
        callbacks: {
          onopen: () => {
            setIsRecording(true);
            const source = audioContextRef.current!.createMediaStreamSource(stream);
            const scriptProcessor = audioContextRef.current!.createScriptProcessor(4096, 1, 1);
            scriptProcessorRef.current = scriptProcessor;

            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const pcmData = floatTo16BitPCM(inputData);
              const base64Data = encode(pcmData);

              sessionPromise.then(session => {
                session.sendRealtimeInput({
                  media: {
                    data: base64Data,
                    mimeType: 'audio/pcm;rate=16000'
                  }
                });
              });
            };

            source.connect(scriptProcessor);
            scriptProcessor.connect(audioContextRef.current!.destination);

            setProgress(prev => ({
              ...prev,
              sessionsCount: prev.sessionsCount + 1,
              streak: prev.streak + 1
            }));
          },
          onmessage: async (message: LiveServerMessage) => {
            if (message.serverContent?.inputTranscription) {
              const text = message.serverContent.inputTranscription.text;
              setTranscriptions(prev => [...prev, { role: 'user', text, timestamp: Date.now() }]);
            }
            if (message.serverContent?.outputTranscription) {
              const text = message.serverContent.outputTranscription.text;
              setTeacherFeedback(text);
              setTranscriptions(prev => [...prev, { role: 'model', text, timestamp: Date.now() }]);

              if (text.includes('👏') || text.includes('棒') || text.includes('標準')) {
                awardPoints(50);
              } else {
                awardPoints(10);
              }
            }

            const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64Audio) {
              setIsAiSpeaking(true);
              const outCtx = outputAudioContextRef.current!;
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outCtx.currentTime);

              const audioBuffer = await decodeAudioData(decode(base64Audio), outCtx, 24000, 1);
              const source = outCtx.createBufferSource();
              source.buffer = audioBuffer;
              source.connect(outCtx.destination);

              source.onended = () => {
                sourcesRef.current.delete(source);
                if (sourcesRef.current.size === 0) setIsAiSpeaking(false);
              };

              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += audioBuffer.duration;
              sourcesRef.current.add(source);
            }

            if (message.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => s.stop());
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
              setIsAiSpeaking(false);
            }
          },
          onerror: (e) => {
            console.error('Gemini error:', e);
            cleanup();
          },
          onclose: () => {
            cleanup();
          }
        }
      });

      sessionRef.current = await sessionPromise;
    } catch (err) {
      console.error('Failed to start recording:', err);
      alert('無法開啟麥克風或連線 API。');
    }
  };

  const renderPhonemeButton = (p: PhonemeInfo) => (
    <button
      key={p.id}
      onClick={() => !isRecording && setSelectedPhoneme(p)}
      disabled={isRecording}
      className={`w-full text-left p-3 rounded-xl border-2 transition-all flex items-center justify-between group ${
        selectedPhoneme.id === p.id 
          ? 'border-orange-500 bg-orange-50 shadow-sm' 
          : 'border-white bg-white/60 hover:border-orange-100'
      } ${isRecording ? 'opacity-50 cursor-not-allowed' : ''}`}
    >
      <div className="flex flex-col">
        <span className="text-xl font-bold text-orange-600">{p.ipa}</span>
        <span className="text-[10px] text-gray-400 font-medium uppercase truncate max-w-[120px]">{p.description}</span>
      </div>
    </button>
  );

  return (
    <div className="min-h-screen flex flex-col bg-orange-50/20">
      <Header progress={progress} />

      <main className="flex-1 max-w-7xl mx-auto w-full p-4 md:p-8 flex flex-col gap-8">
        <div className="flex flex-col md:flex-row justify-between items-center gap-4">
          <div className="text-center md:text-left">
            <h2 className="text-4xl font-black text-gray-800 tracking-tight leading-none mb-2">
              Sound Strong <span className="text-orange-500 underline decoration-orange-200 decoration-4 underline-offset-4">Phonics</span> Coach
            </h2>
          </div>

          <button 
            onClick={() => setShowAchievements(!showAchievements)}
            className={`px-6 py-2.5 rounded-full font-black text-xs uppercase tracking-widest transition-all ${
              showAchievements 
                ? 'bg-orange-500 text-white shadow-orange-200 shadow-xl' 
                : 'bg-white text-gray-400 hover:text-orange-500 border border-orange-100'
            }`}
          >
            {showAchievements ? '返回練習' : '我的成就排行榜'}
          </button>
        </div>

        {!showAchievements && (
          <div className="flex justify-center">
            <div className="bg-white/80 backdrop-blur-sm p-1.5 rounded-2xl border border-orange-100 flex gap-1 shadow-sm">
              {[
                { id: PracticeMode.PHONEME, label: '單字基礎', icon: '🔤' },
                { id: PracticeMode.MINIMAL_PAIRS, label: '對比糾錯', icon: '⚖️' },
                { id: PracticeMode.SENTENCES, label: '句子應用', icon: '📝' }
              ].map(mode => (
                <button
                  key={mode.id}
                  onClick={() => !isRecording && setActiveMode(mode.id)}
                  disabled={isRecording}
                  className={`px-6 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all flex items-center gap-2 ${
                    activeMode === mode.id
                      ? 'bg-orange-500 text-white shadow-md'
                      : 'text-gray-400 hover:text-orange-500 hover:bg-orange-50'
                  } ${isRecording ? 'opacity-50' : ''}`}
                >
                  <span>{mode.icon}</span>
                  {mode.label}
                </button>
              ))}
            </div>
          </div>
        )}

        {showAchievements ? (
          <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
             <GamificationPanel progress={progress} />
          </div>
        ) : (
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 items-start animate-in fade-in duration-500">
            {/* Left: Phoneme Selection */}
            <div className="lg:col-span-4 xl:col-span-3 space-y-6 max-h-[750px] overflow-y-auto pr-2 custom-scrollbar">
              <div>
                <h3 className="text-xs font-black text-gray-400 uppercase tracking-[0.2em] mb-4 flex items-center gap-2">
                  <span className="w-4 h-[2px] bg-orange-300"></span> 課程目錄 Lessons
                </h3>
                <div className="grid grid-cols-1 gap-2">
                  {categorizedPhonemes.consonants.map(renderPhonemeButton)}
                  {categorizedPhonemes.vowels.map(renderPhonemeButton)}
                </div>
              </div>
            </div>

            {/* Right: Main Interface */}
            <div className="lg:col-span-8 xl:col-span-9 space-y-6">
              <div className="bg-white p-6 md:p-10 rounded-[3.5rem] shadow-2xl shadow-orange-100/30 border border-orange-50 relative overflow-hidden">
                <div className="relative z-10 flex flex-col items-center gap-10">
                  <div className="flex flex-col items-center w-full">
                    <div className="flex items-center gap-4 mb-6">
                      <span className="text-8xl font-black text-orange-500 drop-shadow-sm">{selectedPhoneme.ipa}</span>
                      <div className="h-16 w-[2px] bg-gray-100"></div>
                      <span className="text-lg font-black text-gray-700">{selectedPhoneme.description}</span>
                    </div>

                    {/* Dynamic Content Based on Mode */}
                    <div className="w-full animate-in fade-in zoom-in duration-300">
                      {activeMode === PracticeMode.PHONEME && (
                        <div className="flex justify-center gap-2">
                          {selectedPhoneme.exampleWords.map(word => (
                            <span key={word} className="px-6 py-2 bg-orange-50 rounded-2xl text-lg font-black text-orange-600 border border-orange-100 shadow-sm">{word}</span>
                          ))}
                        </div>
                      )}

                      {activeMode === PracticeMode.MINIMAL_PAIRS && (
                        <div className="grid grid-cols-2 gap-4">
                          {selectedPhoneme.minimalPairs?.map((pair, idx) => (
                            <div key={idx} className="bg-orange-50/50 p-6 rounded-[2.5rem] border border-orange-100 flex flex-col items-center gap-2">
                               <div className="flex items-center gap-4 w-full justify-center">
                                 <div className="flex flex-col items-center">
                                   <span className="text-2xl font-black text-gray-800">{pair.word1}</span>
                                   <span className="text-xs font-bold text-orange-400">{pair.targetIpa}</span>
                                 </div>
                                 <span className="text-gray-300 font-bold italic">vs</span>
                                 <div className="flex flex-col items-center">
                                   <span className="text-2xl font-black text-gray-400">{pair.word2}</span>
                                   <span className="text-xs font-bold text-gray-300">{pair.comparisonIpa}</span>
                                 </div>
                               </div>
                            </div>
                          ))}
                        </div>
                      )}

                      {activeMode === PracticeMode.SENTENCES && (
                        <div className="space-y-3">
                          {selectedPhoneme.sentences?.map((sentence, idx) => (
                            <div key={idx} className="bg-white p-5 rounded-[2rem] border-2 border-orange-50 shadow-sm text-center">
                              <p className="text-xl font-bold text-gray-700 leading-relaxed italic">"{sentence}"</p>
                            </div>
                          ))}
                        </div>
                      )}
                    </div>
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-10 w-full items-center">
                    <div className="flex flex-col items-center gap-4">
                      <MouthAnimation 
                        state={selectedPhoneme.animationState} 
                        isActive={isAiSpeaking || isRecording} 
                      />
                    </div>

                    <div className="space-y-6">
                      <div className="bg-orange-50/50 backdrop-blur-sm border border-orange-100 p-8 rounded-[2.5rem] shadow-inner text-center relative min-h-[180px] flex flex-col items-center justify-center transition-all duration-300">
                         {isAiSpeaking && (
                           <div className="absolute -top-3 left-1/2 -translate-x-1/2 flex items-center gap-1.5 bg-white px-4 py-1.5 rounded-full shadow-lg border border-orange-100">
                              {[1,2,3,4,5,6].map(i => (
                                <div key={i} className={`w-1.5 h-4 bg-orange-500 rounded-full animate-bounce`} style={{ animationDelay: `${i * 0.1}s` }}></div>
                              ))}
                           </div>
                         )}
                         <p className="text-gray-800 font-bold text-xl leading-relaxed">
                           {teacherFeedback}
                         </p>
                      </div>

                      <div className="flex flex-col items-center gap-6">
                        <div className="flex items-center gap-6">
                           <button
                            onClick={toggleRecording}
                            className={`group relative flex items-center justify-center w-24 h-24 rounded-full transition-all duration-500 transform active:scale-90 ${
                              isRecording ? 'bg-red-500 shadow-red-200 shadow-2xl scale-110' : 'bg-orange-500 shadow-orange-300 shadow-2xl hover:scale-105'
                            }`}
                          >
                            {isRecording ? <div className="w-10 h-10 bg-white rounded-2xl animate-pulse"></div> : <svg xmlns="http://www.w3.org/2000/svg" className="h-12 w-12 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" /></svg>}
                            <div className={`absolute -inset-3 rounded-full border-4 ${isRecording ? 'border-red-400 animate-ping opacity-20' : 'border-transparent'}`}></div>
                          </button>

                          <button
                            onClick={handleNextPhoneme}
                            disabled={isLastPhoneme || isRecording}
                            className={`flex flex-col items-center justify-center w-20 h-20 rounded-full transition-all border-2 ${
                              isLastPhoneme || isRecording ? 'border-gray-100 bg-gray-50 text-gray-300' : 'border-orange-200 bg-white text-orange-500 hover:border-orange-500 hover:bg-orange-50 shadow-sm'
                            }`}
                          >
                             <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M13 5l7 7-7 7M5 5l7 7-7 7" /></svg>
                             <span className="text-[8px] font-black uppercase mt-1">Next</span>
                          </button>
                        </div>
                        <p className={`text-[10px] font-black tracking-[0.3em] uppercase ${isRecording ? 'text-red-500 animate-pulse' : 'text-orange-400'}`}>
                          {isRecording ? 'Recording...' : 'Tap to Practice'}
                        </p>
                      </div>
                    </div>
                  </div>
                </div>
              </div>

              {/* History Section */}
              <div className="bg-white p-8 rounded-[2.5rem] border border-orange-50 max-h-72 overflow-y-auto custom-scrollbar shadow-sm shadow-orange-50">
                <h4 className="text-[10px] font-black text-gray-400 uppercase tracking-[0.4em] mb-6 flex justify-center">Session History</h4>
                <div className="space-y-4">
                  {transcriptions.length === 0 ? <p className="text-sm text-gray-400 font-medium italic text-center py-6">準備好就點擊錄音鍵開始練習喔！老師在等你。</p> : 
                    transcriptions.map((item, idx) => (
                      <div key={idx} className={`flex ${item.role === 'model' ? 'justify-start' : 'justify-end'}`}>
                        <div className={`max-w-[85%] p-5 rounded-3xl text-sm shadow-sm transition-all hover:shadow-md ${
                          item.role === 'model' ? 'bg-white text-gray-700 rounded-tl-none border border-orange-100 font-medium' : 'bg-gradient-to-br from-orange-400 to-orange-600 text-white rounded-tr-none font-black shadow-orange-100'
                        }`}>{item.text}</div>
                      </div>
                    ))
                  }
                </div>
              </div>
            </div>
          </div>
        )}
      </main>

      <style dangerouslySetInnerHTML={{ __html: `
        .custom-scrollbar::-webkit-scrollbar { width: 5px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: #fffcf9; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #ffe7d1; border-radius: 10px; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #fb923c; }
        @keyframes fade-in { from { opacity: 0; } to { opacity: 1; } }
        @keyframes slide-in-from-bottom-4 { from { transform: translateY(1rem); } to { transform: translateY(0); } }
        @keyframes zoom-in { from { opacity: 0; transform: scale(0.95); } to { opacity: 1; transform: scale(1); } }
        .animate-in { animation: fade-in 0.5s ease-out, slide-in-from-bottom-4 0.5s ease-out; }
      `}} />
    </div>
  );
};

export default App;

export enum PhonemeType {
  CONSONANT = 'CONSONANT',
  VOWEL = 'VOWEL',
  DIPHTHONG = 'DIPHTHONG',
  SPECIAL = 'SPECIAL',
}

export enum PracticeMode {
  PHONEME = 'PHONEME',
  MINIMAL_PAIRS = 'MINIMAL_PAIRS',
  SENTENCES = 'SENTENCES',
}

export interface MinimalPair {
  word1: string;
  word2: string;
  targetIpa: string;
  comparisonIpa: string;
}

export interface PhonemeInfo {
  id: string;
  ipa: string;
  exampleWords: string[];
  type: PhonemeType;
  description: string;
  tips: string;
  commonMistakes: string;
  animationState: 'neutral' | 'open' | 'tongue-out' | 'tongue-up' | 'rounded';
  minimalPairs?: MinimalPair[];
  sentences?: string[];
}

export interface TranscriptionItem {
  role: 'user' | 'model';
  text: string;
  timestamp: number;
}

export interface Badge {
  id: string;
  name: string;
  description: string;
  icon: string;
  color: string;
}

export interface UserProgress {
  points: number;
  level: number;
  streak: number;
  lastPracticeDate: string | null;
  badges: string[]; // IDs of earned badges
  sessionsCount: number;
}

export interface LeaderboardEntry {
  name: string;
  points: number;
  isCurrentUser?: boolean;
}

import React, { useState, useCallback, useRef, useMemo, useEffect } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import Header from './components/Header';
import MouthAnimation from './components/MouthAnimation';
import GamificationPanel from './components/GamificationPanel';
import { PHONEMES, TEACHER_SYSTEM_PROMPT } from './constants';
import { PhonemeInfo, TranscriptionItem, PhonemeType, UserProgress, PracticeMode } from './types';
import { encode, decode, decodeAudioData, floatTo16BitPCM } from './services/audioUtils';

const STORAGE_KEY = 'sound_strong_user_progress';

const DEFAULT_PROGRESS: UserProgress = {
  points: 0,
  level: 1,
  streak: 0,
  lastPracticeDate: null,
  badges: [],
  sessionsCount: 0,
};

const App: React.FC = () => {
  const [selectedPhoneme, setSelectedPhoneme] = useState<PhonemeInfo>(PHONEMES[0]);
  const [activeMode, setActiveMode] = useState<PracticeMode>(PracticeMode.PHONEME);
  const [isRecording, setIsRecording] = useState(false);
  const [transcriptions, setTranscriptions] = useState<TranscriptionItem[]>([]);
  const [teacherFeedback, setTeacherFeedback] = useState<string>("老師正在聽你練習喔！準備好了就點擊下方按鈕開始吧。");
  const [isAiSpeaking, setIsAiSpeaking] = useState(false);
  const [showAchievements, setShowAchievements] = useState(false);
  const [searchQuery, setSearchQuery] = useState("");

  // Gamification State
  const [progress, setProgress] = useState<UserProgress>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : DEFAULT_PROGRESS;
  });

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(progress));
  }, [progress]);

  // Search Logic
  const filteredPhonemes = useMemo(() => {
    if (!searchQuery.trim()) return PHONEMES;
    const query = searchQuery.toLowerCase();
    return PHONEMES.filter(p => 
      p.ipa.toLowerCase().includes(query) || 
      p.description.toLowerCase().includes(query) ||
      p.exampleWords.some(w => w.toLowerCase().includes(query))
    );
  }, [searchQuery]);

  // Grouping phonemes for better UX
  const categorizedPhonemes = useMemo(() => {
    return {
      vowels: filteredPhonemes.filter(p => p.type === PhonemeType.VOWEL),
      diphthongs: filteredPhonemes.filter(p => p.type === PhonemeType.DIPHTHONG),
      consonants: filteredPhonemes.filter(p => p.type === PhonemeType.CONSONANT),
      special: filteredPhonemes.filter(p => p.type === PhonemeType.SPECIAL),
    };
  }, [filteredPhonemes]);

  // Navigation Logic
  const currentIndex = useMemo(() => 
    PHONEMES.findIndex(p => p.id === selectedPhoneme.id),
  [selectedPhoneme]);

  const isLastPhoneme = currentIndex === PHONEMES.length - 1;

  const handleNextPhoneme = useCallback(() => {
    if (!isLastPhoneme && !isRecording) {
      const nextPhoneme = PHONEMES[currentIndex + 1];
      setSelectedPhoneme(nextPhoneme);
      setTeacherFeedback(`切換到下一課：${nextPhoneme.ipa}。準備好就可以點擊錄音鈕練習囉！`);
      setTranscriptions([]); 
    }
  }, [currentIndex, isLastPhoneme, isRecording]);

  // Refs for audio processing
  const audioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const sessionRef = useRef<any>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const scriptProcessorRef = useRef<ScriptProcessorNode | null>(null);

  const cleanup = useCallback(() => {
    if (sessionRef.current) {
      sessionRef.current = null;
    }
    if (scriptProcessorRef.current) {
      scriptProcessorRef.current.disconnect();
      scriptProcessorRef.current = null;
    }
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
    sourcesRef.current.forEach(source => source.stop());
    sourcesRef.current.clear();
    setIsRecording(false);
    setIsAiSpeaking(false);
  }, []);

  const awardPoints = useCallback((amount: number) => {
    setProgress(prev => {
      const multiplier = activeMode === PracticeMode.SENTENCES ? 3 : activeMode === PracticeMode.MINIMAL_PAIRS ? 2 : 1;
      const actualAward = amount * multiplier;
      const newPoints = prev.points + actualAward;
      const newLevel = Math.floor(newPoints / 500) + 1;
      const newBadges = [...prev.badges];

      if (!newBadges.includes('first_step')) newBadges.push('first_step');
      if (actualAward >= 100 && !newBadges.includes('perfect_score')) newBadges.push('perfect_score');

      return {
        ...prev,
        points: newPoints,
        level: newLevel,
        badges: newBadges,
      };
    });
  }, [activeMode]);

  const toggleRecording = async () => {
    if (isRecording) {
      cleanup();
      return;
    }

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

      if (!audioContextRef.current) {
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      }
      if (!outputAudioContextRef.current) {
        outputAudioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      }

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      const modeContext = activeMode === PracticeMode.MINIMAL_PAIRS 
        ? `目前的模式是【最小對立體對比練習】。請特別注意 ${selectedPhoneme.minimalPairs?.[0]?.word1} 與 ${selectedPhoneme.minimalPairs?.[0]?.word2} 之間的差異。`
        : activeMode === PracticeMode.SENTENCES
        ? `目前的模式是【句子應用練習】。請注意句子的流暢度與語調。`
        : `目前的模式是【基礎單字發音】。`;

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          systemInstruction: TEACHER_SYSTEM_PROMPT + 
            `\n${modeContext}\n` +
            `練習主題：${selectedPhoneme.ipa}\n` +
            `發音祕訣：${selectedPhoneme.tips}\n` +
            `常見錯誤：${selectedPhoneme.commonMistakes}`,
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } },
          },
          inputAudioTranscription: {},
          outputAudioTranscription: {},
        },
        callbacks: {
          onopen: () => {
            setIsRecording(true);
            const source = audioContextRef.current!.createMediaStreamSource(stream);
            const scriptProcessor = audioContextRef.current!.createScriptProcessor(4096, 1, 1);
            scriptProcessorRef.current = scriptProcessor;

            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const pcmData = floatTo16BitPCM(inputData);
              const base64Data = encode(pcmData);

              sessionPromise.then(session => {
                session.sendRealtimeInput({
                  media: {
                    data: base64Data,
                    mimeType: 'audio/pcm;rate=16000'
                  }
                });
              });
            };

            source.connect(scriptProcessor);
            scriptProcessor.connect(audioContextRef.current!.destination);

            setProgress(prev => ({
              ...prev,
              sessionsCount: prev.sessionsCount + 1,
              streak: prev.streak + 1
            }));
          },
          onmessage: async (message: LiveServerMessage) => {
            if (message.serverContent?.inputTranscription) {
              const text = message.serverContent.inputTranscription.text;
              setTranscriptions(prev => [...prev, { role: 'user', text, timestamp: Date.now() }]);
            }
            if (message.serverContent?.outputTranscription) {
              const text = message.serverContent.outputTranscription.text;
              setTeacherFeedback(text);
              setTranscriptions(prev => [...prev, { role: 'model', text, timestamp: Date.now() }]);

              if (text.includes('👏') || text.includes('棒') || text.includes('標準')) {
                awardPoints(50);
              } else {
                awardPoints(10);
              }
            }

            const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64Audio) {
              setIsAiSpeaking(true);
              const outCtx = outputAudioContextRef.current!;
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outCtx.currentTime);

              const audioBuffer = await decodeAudioData(decode(base64Audio), outCtx, 24000, 1);
              const source = outCtx.createBufferSource();
              source.buffer = audioBuffer;
              source.connect(outCtx.destination);

              source.onended = () => {
                sourcesRef.current.delete(source);
                if (sourcesRef.current.size === 0) setIsAiSpeaking(false);
              };

              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += audioBuffer.duration;
              sourcesRef.current.add(source);
            }

            if (message.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => s.stop());
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
              setIsAiSpeaking(false);
            }
          },
          onerror: (e) => {
            console.error('Gemini error:', e);
            cleanup();
          },
          onclose: () => {
            cleanup();
          }
        }
      });

      sessionRef.current = await sessionPromise;
    } catch (err) {
      console.error('Failed to start recording:', err);
      alert('無法開啟麥克風或連線 API。');
    }
  };

  const renderPhonemeButton = (p: PhonemeInfo) => (
    <button
      key={p.id}
      onClick={() => !isRecording && setSelectedPhoneme(p)}
      disabled={isRecording}
      className={`w-full text-left p-3 rounded-xl border-2 transition-all flex items-center justify-between group ${
        selectedPhoneme.id === p.id 
          ? 'border-orange-500 bg-orange-50 shadow-sm' 
          : 'border-white bg-white/60 hover:border-orange-100'
      } ${isRecording ? 'opacity-50 cursor-not-allowed' : ''}`}
    >
      <div className="flex flex-col">
        <span className="text-xl font-bold text-orange-600">{p.ipa}</span>
        <span className="text-[10px] text-gray-400 font-medium uppercase truncate max-w-[120px]">{p.description}</span>
      </div>
      {p.type === PhonemeType.DIPHTHONG && <span className="text-[10px] bg-blue-100 text-blue-600 px-1.5 py-0.5 rounded font-black">D</span>}
      {p.type === PhonemeType.SPECIAL && <span className="text-[10px] bg-purple-100 text-purple-600 px-1.5 py-0.5 rounded font-black">S</span>}
    </button>
  );

  return (
    <div className="min-h-screen flex flex-col bg-orange-50/20">
      <Header progress={progress} />

      <main className="flex-1 max-w-7xl mx-auto w-full p-4 md:p-8 flex flex-col gap-8">
        <div className="flex flex-col md:flex-row justify-between items-center gap-4">
          <div className="text-center md:text-left">
            <h2 className="text-4xl font-black text-gray-800 tracking-tight leading-none mb-2">
              Sound Strong <span className="text-orange-500 underline decoration-orange-200 decoration-4 underline-offset-4">Phonics</span> Coach
            </h2>
          </div>

          <button 
            onClick={() => setShowAchievements(!showAchievements)}
            className={`px-6 py-2.5 rounded-full font-black text-xs uppercase tracking-widest transition-all ${
              showAchievements 
                ? 'bg-orange-500 text-white shadow-orange-200 shadow-xl' 
                : 'bg-white text-gray-400 hover:text-orange-500 border border-orange-100'
            }`}
          >
            {showAchievements ? '返回練習' : '我的成就排行榜'}
          </button>
        </div>

        {!showAchievements && (
          <div className="flex justify-center">
            <div className="bg-white/80 backdrop-blur-sm p-1.5 rounded-2xl border border-orange-100 flex gap-1 shadow-sm">
              {[
                { id: PracticeMode.PHONEME, label: '單字基礎', icon: '🔤' },
                { id: PracticeMode.MINIMAL_PAIRS, label: '對比糾錯', icon: '⚖️' },
                { id: PracticeMode.SENTENCES, label: '句子應用', icon: '📝' }
              ].map(mode => (
                <button
                  key={mode.id}
                  onClick={() => !isRecording && setActiveMode(mode.id)}
                  disabled={isRecording}
                  className={`px-6 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all flex items-center gap-2 ${
                    activeMode === mode.id
                      ? 'bg-orange-500 text-white shadow-md'
                      : 'text-gray-400 hover:text-orange-500 hover:bg-orange-50'
                  } ${isRecording ? 'opacity-50' : ''}`}
                >
                  <span>{mode.icon}</span>
                  {mode.label}
                </button>
              ))}
            </div>
          </div>
        )}

        {showAchievements ? (
          <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
             <GamificationPanel progress={progress} />
          </div>
        ) : (
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 items-start animate-in fade-in duration-500">
            {/* Left: Phoneme Selection with Search */}
            <div className="lg:col-span-4 xl:col-span-3 space-y-4 max-h-[750px] flex flex-col">
              <div className="relative">
                <input 
                  type="text" 
                  placeholder="搜尋音標或單字..." 
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="w-full pl-10 pr-4 py-2.5 rounded-2xl bg-white border border-orange-100 text-sm focus:ring-2 focus:ring-orange-300 focus:border-orange-300 outline-none transition-all shadow-sm"
                />
                <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 absolute left-3.5 top-3.5 text-orange-300" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
                </svg>
              </div>

              <div className="flex-1 overflow-y-auto pr-2 custom-scrollbar space-y-6">
                {Object.entries(categorizedPhonemes).map(([key, list]) => (
                  list.length > 0 && (
                    <div key={key}>
                      <h3 className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em] mb-3 flex items-center gap-2 sticky top-0 bg-white/80 backdrop-blur-md py-1 z-10">
                        <span className="w-3 h-[2px] bg-orange-200"></span> 
                        {key.toUpperCase()} ({list.length})
                      </h3>
                      <div className="grid grid-cols-1 gap-1.5">
                        {list.map(renderPhonemeButton)}
                      </div>
                    </div>
                  )
                ))}
                {filteredPhonemes.length === 0 && (
                  <div className="text-center py-10">
                    <p className="text-xs font-bold text-gray-400">找不到相關音標 🔍</p>
                  </div>
                )}
              </div>
            </div>

            {/* Right: Main Interface */}
            <div className="lg:col-span-8 xl:col-span-9 space-y-6">
              <div className="bg-white p-6 md:p-10 rounded-[3.5rem] shadow-2xl shadow-orange-100/30 border border-orange-50 relative overflow-hidden">
                <div className="relative z-10 flex flex-col items-center gap-10">
                  <div className="flex flex-col items-center w-full">
                    <div className="flex items-center gap-4 mb-6">
                      <span className="text-8xl font-black text-orange-500 drop-shadow-sm">{selectedPhoneme.ipa}</span>
                      <div className="h-16 w-[2px] bg-gray-100"></div>
                      <span className="text-lg font-black text-gray-700">{selectedPhoneme.description}</span>
                    </div>

                    {/* Dynamic Content Based on Mode */}
                    <div className="w-full animate-in fade-in zoom-in duration-300">
                      {activeMode === PracticeMode.PHONEME && (
                        <div className="flex flex-wrap justify-center gap-2">
                          {selectedPhoneme.exampleWords.map(word => (
                            <span key={word} className="px-6 py-2 bg-orange-50 rounded-2xl text-lg font-black text-orange-600 border border-orange-100 shadow-sm">{word}</span>
                          ))}
                        </div>
                      )}

                      {activeMode === PracticeMode.MINIMAL_PAIRS && (
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                          {selectedPhoneme.minimalPairs?.length ? (
                            selectedPhoneme.minimalPairs.map((pair, idx) => (
                              <div key={idx} className="bg-orange-50/50 p-6 rounded-[2.5rem] border border-orange-100 flex flex-col items-center gap-2">
                                <div className="flex items-center gap-4 w-full justify-center">
                                  <div className="flex flex-col items-center">
                                    <span className="text-2xl font-black text-gray-800">{pair.word1}</span>
                                    <span className="text-xs font-bold text-orange-400">{pair.targetIpa}</span>
                                  </div>
                                  <span className="text-gray-300 font-bold italic">vs</span>
                                  <div className="flex flex-col items-center">
                                    <span className="text-2xl font-black text-gray-400">{pair.word2}</span>
                                    <span className="text-xs font-bold text-gray-300">{pair.comparisonIpa}</span>
                                  </div>
                                </div>
                              </div>
                            ))
                          ) : (
                            <div className="col-span-2 text-center py-6 text-gray-400 font-bold bg-gray-50 rounded-3xl border border-dashed">此音標無建議對立練習</div>
                          )}
                        </div>
                      )}

                      {activeMode === PracticeMode.SENTENCES && (
                        <div className="space-y-3">
                          {selectedPhoneme.sentences?.map((sentence, idx) => (
                            <div key={idx} className="bg-white p-5 rounded-[2rem] border-2 border-orange-50 shadow-sm text-center">
                              <p className="text-xl font-bold text-gray-700 leading-relaxed italic">"{sentence}"</p>
                            </div>
                          ))}
                        </div>
                      )}
                    </div>
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-10 w-full items-center">
                    <div className="flex flex-col items-center gap-4">
                      <MouthAnimation 
                        state={selectedPhoneme.animationState || 'neutral'} 
                        isActive={isAiSpeaking || isRecording} 
                      />
                    </div>

                    <div className="space-y-6">
                      <div className="bg-orange-50/50 backdrop-blur-sm border border-orange-100 p-8 rounded-[2.5rem] shadow-inner text-center relative min-h-[180px] flex flex-col items-center justify-center transition-all duration-300">
                         {isAiSpeaking && (
                           <div className="absolute -top-3 left-1/2 -translate-x-1/2 flex items-center gap-1.5 bg-white px-4 py-1.5 rounded-full shadow-lg border border-orange-100">
                              {[1,2,3,4,5,6].map(i => (
                                <div key={i} className={`w-1.5 h-4 bg-orange-500 rounded-full animate-bounce`} style={{ animationDelay: `${i * 0.1}s` }}></div>
                              ))}
                           </div>
                         )}
                         <p className="text-gray-800 font-bold text-xl leading-relaxed">
                           {teacherFeedback}
                         </p>
                      </div>

                      <div className="flex flex-col items-center gap-6">
                        <div className="flex items-center gap-6">
                           <button
                            onClick={toggleRecording}
                            className={`group relative flex items-center justify-center w-24 h-24 rounded-full transition-all duration-500 transform active:scale-90 ${
                              isRecording ? 'bg-red-500 shadow-red-200 shadow-2xl scale-110' : 'bg-orange-500 shadow-orange-300 shadow-2xl hover:scale-105'
                            }`}
                          >
                            {isRecording ? <div className="w-10 h-10 bg-white rounded-2xl animate-pulse"></div> : <svg xmlns="http://www.w3.org/2000/svg" className="h-12 w-12 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" /></svg>}
                            <div className={`absolute -inset-3 rounded-full border-4 ${isRecording ? 'border-red-400 animate-ping opacity-20' : 'border-transparent'}`}></div>
                          </button>

                          <button
                            onClick={handleNextPhoneme}
                            disabled={isLastPhoneme || isRecording}
                            className={`flex flex-col items-center justify-center w-20 h-20 rounded-full transition-all border-2 ${
                              isLastPhoneme || isRecording ? 'border-gray-100 bg-gray-50 text-gray-300' : 'border-orange-200 bg-white text-orange-500 hover:border-orange-500 hover:bg-orange-50 shadow-sm'
                            }`}
                          >
                             <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M13 5l7 7-7 7M5 5l7 7-7 7" /></svg>
                             <span className="text-[8px] font-black uppercase mt-1">Next</span>
                          </button>
                        </div>
                        <p className={`text-[10px] font-black tracking-[0.3em] uppercase ${isRecording ? 'text-red-500 animate-pulse' : 'text-orange-400'}`}>
                          {isRecording ? 'Recording...' : 'Tap to Practice'}
                        </p>
                      </div>
                    </div>
                  </div>
                </div>
              </div>

              {/* History Section */}
              <div className="bg-white p-8 rounded-[2.5rem] border border-orange-50 max-h-72 overflow-y-auto custom-scrollbar shadow-sm shadow-orange-50">
                <h4 className="text-[10px] font-black text-gray-400 uppercase tracking-[0.4em] mb-6 flex justify-center">Session History</h4>
                <div className="space-y-4">
                  {transcriptions.length === 0 ? <p className="text-sm text-gray-400 font-medium italic text-center py-6">準備好就點擊錄音鍵開始練習喔！老師在等你。</p> : 
                    transcriptions.map((item, idx) => (
                      <div key={idx} className={`flex ${item.role === 'model' ? 'justify-start' : 'justify-end'}`}>
                        <div className={`max-w-[85%] p-5 rounded-3xl text-sm shadow-sm transition-all hover:shadow-md ${
                          item.role === 'model' ? 'bg-white text-gray-700 rounded-tl-none border border-orange-100 font-medium' : 'bg-gradient-to-br from-orange-400 to-orange-600 text-white rounded-tr-none font-black shadow-orange-100'
                        }`}>{item.text}</div>
                      </div>
                    ))
                  }
                </div>
              </div>
            </div>
          </div>
        )}
      </main>

      <style dangerouslySetInnerHTML={{ __html: `
        .custom-scrollbar::-webkit-scrollbar { width: 5px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: #fffcf9; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #ffe7d1; border-radius: 10px; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #fb923c; }
        @keyframes fade-in { from { opacity: 0; } to { opacity: 1; } }
        @keyframes slide-in-from-bottom-4 { from { transform: translateY(1rem); } to { transform: translateY(0); } }
        @keyframes zoom-in { from { opacity: 0; transform: scale(0.95); } to { opacity: 1; transform: scale(1); } }
        .animate-in { animation: fade-in 0.5s ease-out, slide-in-from-bottom-4 0.5s ease-out; }
      `}} />
    </div>
  );
};

export default App;

import React, { useState, useCallback, useRef, useMemo, useEffect } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import Header from './components/Header';
import MouthAnimation from './components/MouthAnimation';
import GamificationPanel from './components/GamificationPanel';
import { PHONEMES, TEACHER_SYSTEM_PROMPT } from './constants';
import { PhonemeInfo, TranscriptionItem, PhonemeType, UserProgress, PracticeMode } from './types';
import { encode, decode, decodeAudioData, floatTo16BitPCM } from './services/audioUtils';

const STORAGE_KEY = 'sound_strong_user_progress';

const DEFAULT_PROGRESS: UserProgress = {
  points: 0,
  level: 1,
  streak: 0,
  lastPracticeDate: null,
  badges: [],
  sessionsCount: 0,
};

const App: React.FC = () => {
  const [selectedPhoneme, setSelectedPhoneme] = useState<PhonemeInfo>(PHONEMES[0]);
  const [activeMode, setActiveMode] = useState<PracticeMode>(PracticeMode.PHONEME);
  const [isRecording, setIsRecording] = useState(false);
  const [transcriptions, setTranscriptions] = useState<TranscriptionItem[]>([]);
  const [teacherFeedback, setTeacherFeedback] = useState<string>("老師正在聽你練習喔！準備好了就點擊下方按鈕開始吧。");
  const [isAiSpeaking, setIsAiSpeaking] = useState(false);
  const [showAchievements, setShowAchievements] = useState(false);
  const [searchQuery, setSearchQuery] = useState("");

  // Gamification State
  const [progress, setProgress] = useState<UserProgress>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : DEFAULT_PROGRESS;
  });

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(progress));
  }, [progress]);

  // Search Logic
  const filteredPhonemes = useMemo(() => {
    if (!searchQuery.trim()) return PHONEMES;
    const query = searchQuery.toLowerCase();
    return PHONEMES.filter(p => 
      p.ipa.toLowerCase().includes(query) || 
      p.description.toLowerCase().includes(query) ||
      p.exampleWords.some(w => w.toLowerCase().includes(query))
    );
  }, [searchQuery]);

  // Grouping phonemes for better UX
  const categorizedPhonemes = useMemo(() => {
    return {
      vowels: filteredPhonemes.filter(p => p.type === PhonemeType.VOWEL),
      diphthongs: filteredPhonemes.filter(p => p.type === PhonemeType.DIPHTHONG),
      consonants: filteredPhonemes.filter(p => p.type === PhonemeType.CONSONANT),
      special: filteredPhonemes.filter(p => p.type === PhonemeType.SPECIAL),
    };
  }, [filteredPhonemes]);

  // Navigation Logic
  const currentIndex = useMemo(() => 
    PHONEMES.findIndex(p => p.id === selectedPhoneme.id),
  [selectedPhoneme]);

  const isLastPhoneme = currentIndex === PHONEMES.length - 1;

  const handleNextPhoneme = useCallback(() => {
    if (!isLastPhoneme && !isRecording) {
      const nextPhoneme = PHONEMES[currentIndex + 1];
      setSelectedPhoneme(nextPhoneme);
      setTeacherFeedback(`切換到下一課：${nextPhoneme.ipa}。準備好就可以點擊錄音鈕練習囉！`);
      setTranscriptions([]); 
    }
  }, [currentIndex, isLastPhoneme, isRecording]);

  // Refs for audio processing
  const audioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const sessionRef = useRef<any>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const scriptProcessorRef = useRef<ScriptProcessorNode | null>(null);

  const cleanup = useCallback(() => {
    if (sessionRef.current) {
      sessionRef.current = null;
    }
    if (scriptProcessorRef.current) {
      scriptProcessorRef.current.disconnect();
      scriptProcessorRef.current = null;
    }
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
    sourcesRef.current.forEach(source => source.stop());
    sourcesRef.current.clear();
    setIsRecording(false);
    setIsAiSpeaking(false);
  }, []);

  const awardPoints = useCallback((amount: number) => {
    setProgress(prev => {
      const multiplier = activeMode === PracticeMode.SENTENCES ? 3 : activeMode === PracticeMode.MINIMAL_PAIRS ? 2 : 1;
      const actualAward = amount * multiplier;
      const newPoints = prev.points + actualAward;
      const newLevel = Math.floor(newPoints / 500) + 1;
      const newBadges = [...prev.badges];

      if (!newBadges.includes('first_step')) newBadges.push('first_step');
      if (actualAward >= 100 && !newBadges.includes('perfect_score')) newBadges.push('perfect_score');

      return {
        ...prev,
        points: newPoints,
        level: newLevel,
        badges: newBadges,
      };
    });
  }, [activeMode]);

  const toggleRecording = async () => {
    if (isRecording) {
      cleanup();
      return;
    }

    try {
      // Use the injected API_KEY exclusively from process.env
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      if (!audioContextRef.current) {
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      }
      if (!outputAudioContextRef.current) {
        outputAudioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      }

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      const modeContext = activeMode === PracticeMode.MINIMAL_PAIRS 
        ? `目前的模式是【最小對立體對比練習】。請特別注意 ${selectedPhoneme.minimalPairs?.[0]?.word1} 與 ${selectedPhoneme.minimalPairs?.[0]?.word2} 之間的差異。`
        : activeMode === PracticeMode.SENTENCES
        ? `目前的模式是【句子應用練習】。請注意句子的流暢度與語調。`
        : `目前的模式是【基礎單字發音】。`;

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          systemInstruction: TEACHER_SYSTEM_PROMPT + 
            `\n${modeContext}\n` +
            `練習主題：${selectedPhoneme.ipa}\n` +
            `發音祕訣：${selectedPhoneme.tips}\n` +
            `常見錯誤：${selectedPhoneme.commonMistakes}`,
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } },
          },
          inputAudioTranscription: {},
          outputAudioTranscription: {},
        },
        callbacks: {
          onopen: () => {
            setIsRecording(true);
            const source = audioContextRef.current!.createMediaStreamSource(stream);
            const scriptProcessor = audioContextRef.current!.createScriptProcessor(4096, 1, 1);
            scriptProcessorRef.current = scriptProcessor;

            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const pcmData = floatTo16BitPCM(inputData);
              const base64Data = encode(pcmData);

              sessionPromise.then(session => {
                session.sendRealtimeInput({
                  media: {
                    data: base64Data,
                    mimeType: 'audio/pcm;rate=16000'
                  }
                });
              });
            };

            source.connect(scriptProcessor);
            scriptProcessor.connect(audioContextRef.current!.destination);

            setProgress(prev => ({
              ...prev,
              sessionsCount: prev.sessionsCount + 1,
              streak: prev.streak + 1
            }));
          },
          onmessage: async (message: LiveServerMessage) => {
            if (message.serverContent?.inputTranscription) {
              const text = message.serverContent.inputTranscription.text;
              setTranscriptions(prev => [...prev, { role: 'user', text, timestamp: Date.now() }]);
            }
            if (message.serverContent?.outputTranscription) {
              const text = message.serverContent.outputTranscription.text;
              setTeacherFeedback(text);
              setTranscriptions(prev => [...prev, { role: 'model', text, timestamp: Date.now() }]);

              if (text.includes('👏') || text.includes('棒') || text.includes('標準')) {
                awardPoints(50);
              } else {
                awardPoints(10);
              }
            }

            const base64Audio = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (base64Audio) {
              setIsAiSpeaking(true);
              const outCtx = outputAudioContextRef.current!;
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outCtx.currentTime);

              const audioBuffer = await decodeAudioData(decode(base64Audio), outCtx, 24000, 1);
              const source = outCtx.createBufferSource();
              source.buffer = audioBuffer;
              source.connect(outCtx.destination);

              source.onended = () => {
                sourcesRef.current.delete(source);
                if (sourcesRef.current.size === 0) setIsAiSpeaking(false);
              };

              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += audioBuffer.duration;
              sourcesRef.current.add(source);
            }

            if (message.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => s.stop());
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
              setIsAiSpeaking(false);
            }
          },
          onerror: (e) => {
            console.error('Gemini error:', e);
            cleanup();
          },
          onclose: () => {
            cleanup();
          }
        }
      });

      sessionRef.current = await sessionPromise;
    } catch (err) {
      console.error('Failed to start recording:', err);
      alert('無法開啟麥克風或連線 API。');
    }
  };

  const renderPhonemeButton = (p: PhonemeInfo) => (
    <button
      key={p.id}
      onClick={() => !isRecording && setSelectedPhoneme(p)}
      disabled={isRecording}
      className={`w-full text-left p-3 rounded-xl border-2 transition-all flex items-center justify-between group ${
        selectedPhoneme.id === p.id 
          ? 'border-orange-500 bg-orange-50 shadow-sm' 
          : 'border-white bg-white/60 hover:border-orange-100'
      } ${isRecording ? 'opacity-50 cursor-not-allowed' : ''}`}
    >
      <div className="flex flex-col">
        <span className="text-xl font-bold text-orange-600">{p.ipa}</span>
        <span className="text-[10px] text-gray-400 font-medium uppercase truncate max-w-[120px]">{p.description}</span>
      </div>
      {p.type === PhonemeType.DIPHTHONG && <span className="text-[10px] bg-blue-100 text-blue-600 px-1.5 py-0.5 rounded font-black">D</span>}
      {p.type === PhonemeType.SPECIAL && <span className="text-[10px] bg-purple-100 text-purple-600 px-1.5 py-0.5 rounded font-black">S</span>}
    </button>
  );

  return (
    <div className="min-h-screen flex flex-col bg-orange-50/20">
      <Header progress={progress} />

      <main className="flex-1 max-w-7xl mx-auto w-full p-4 md:p-8 flex flex-col gap-8">
        <div className="flex flex-col md:flex-row justify-between items-center gap-4">
          <div className="text-center md:text-left">
            <h2 className="text-4xl font-black text-gray-800 tracking-tight leading-none mb-2">
              Sound Strong <span className="text-orange-500 underline decoration-orange-200 decoration-4 underline-offset-4">Phonics</span> Coach
            </h2>
          </div>

          <button 
            onClick={() => setShowAchievements(!showAchievements)}
            className={`px-6 py-2.5 rounded-full font-black text-xs uppercase tracking-widest transition-all ${
              showAchievements 
                ? 'bg-orange-500 text-white shadow-orange-200 shadow-xl' 
                : 'bg-white text-gray-400 hover:text-orange-500 border border-orange-100'
            }`}
          >
            {showAchievements ? '返回練習' : '我的成就排行榜'}
          </button>
        </div>

        {!showAchievements && (
          <div className="flex justify-center">
            <div className="bg-white/80 backdrop-blur-sm p-1.5 rounded-2xl border border-orange-100 flex gap-1 shadow-sm">
              {[
                { id: PracticeMode.PHONEME, label: '單字基礎', icon: '🔤' },
                { id: PracticeMode.MINIMAL_PAIRS, label: '對比糾錯', icon: '⚖️' },
                { id: PracticeMode.SENTENCES, label: '句子應用', icon: '📝' }
              ].map(mode => (
                <button
                  key={mode.id}
                  onClick={() => !isRecording && setActiveMode(mode.id)}
                  disabled={isRecording}
                  className={`px-6 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all flex items-center gap-2 ${
                    activeMode === mode.id
                      ? 'bg-orange-500 text-white shadow-md'
                      : 'text-gray-400 hover:text-orange-500 hover:bg-orange-50'
                  } ${isRecording ? 'opacity-50' : ''}`}
                >
                  <span>{mode.icon}</span>
                  {mode.label}
                </button>
              ))}
            </div>
          </div>
        )}

        {showAchievements ? (
          <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
             <GamificationPanel progress={progress} />
          </div>
        ) : (
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 items-start animate-in fade-in duration-500">
            {/* Left: Phoneme Selection with Search */}
            <div className="lg:col-span-4 xl:col-span-3 space-y-4 max-h-[750px] flex flex-col">
              <div className="relative">
                <input 
                  type="text" 
                  placeholder="搜尋音標或單字..." 
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="w-full pl-10 pr-4 py-2.5 rounded-2xl bg-white border border-orange-100 text-sm focus:ring-2 focus:ring-orange-300 focus:border-orange-300 outline-none transition-all shadow-sm"
                />
                <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 absolute left-3.5 top-3.5 text-orange-300" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
                </svg>
              </div>

              <div className="flex-1 overflow-y-auto pr-2 custom-scrollbar space-y-6">
                {/* Fix: Cast categorizedPhonemes entries to preserve array types for PhonemeInfo items */}
                {(Object.entries(categorizedPhonemes) as [string, PhonemeInfo[]][]).map(([key, list]) => (
                  list.length > 0 && (
                    <div key={key}>
                      <h3 className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em] mb-3 flex items-center gap-2 sticky top-0 bg-white/80 backdrop-blur-md py-1 z-10">
                        <span className="w-3 h-[2px] bg-orange-200"></span> 
                        {key.toUpperCase()} ({list.length})
                      </h3>
                      <div className="grid grid-cols-1 gap-1.5">
                        {list.map(renderPhonemeButton)}
                      </div>
                    </div>
                  )
                ))}
                {filteredPhonemes.length === 0 && (
                  <div className="text-center py-10">
                    <p className="text-xs font-bold text-gray-400">找不到相關音標 🔍</p>
                  </div>
                )}
              </div>
            </div>

            {/* Right: Main Interface */}
            <div className="lg:col-span-8 xl:col-span-9 space-y-6">
              <div className="bg-white p-6 md:p-10 rounded-[3.5rem] shadow-2xl shadow-orange-100/30 border border-orange-50 relative overflow-hidden">
                <div className="relative z-10 flex flex-col items-center gap-10">
                  <div className="flex flex-col items-center w-full">
                    <div className="flex items-center gap-4 mb-6">
                      <span className="text-8xl font-black text-orange-500 drop-shadow-sm">{selectedPhoneme.ipa}</span>
                      <div className="h-16 w-[2px] bg-gray-100"></div>
                      <span className="text-lg font-black text-gray-700">{selectedPhoneme.description}</span>
                    </div>

                    {/* Dynamic Content Based on Mode */}
                    <div className="w-full animate-in fade-in zoom-in duration-300">
                      {activeMode === PracticeMode.PHONEME && (
                        <div className="flex flex-wrap justify-center gap-2">
                          {selectedPhoneme.exampleWords.map(word => (
                            <span key={word} className="px-6 py-2 bg-orange-50 rounded-2xl text-lg font-black text-orange-600 border border-orange-100 shadow-sm">{word}</span>
                          ))}
                        </div>
                      )}

                      {activeMode === PracticeMode.MINIMAL_PAIRS && (
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                          {selectedPhoneme.minimalPairs?.length ? (
                            selectedPhoneme.minimalPairs.map((pair, idx) => (
                              <div key={idx} className="bg-orange-50/50 p-6 rounded-[2.5rem] border border-orange-100 flex flex-col items-center gap-2">
                                <div className="flex items-center gap-4 w-full justify-center">
                                  <div className="flex flex-col items-center">
                                    <span className="text-2xl font-black text-gray-800">{pair.word1}</span>
                                    <span className="text-xs font-bold text-orange-400">{pair.targetIpa}</span>
                                  </div>
                                  <span className="text-gray-300 font-bold italic">vs</span>
                                  <div className="flex flex-col items-center">
                                    <span className="text-2xl font-black text-gray-400">{pair.word2}</span>
                                    <span className="text-xs font-bold text-gray-300">{pair.comparisonIpa}</span>
                                  </div>
                                </div>
                              </div>
                            ))
                          ) : (
                            <div className="col-span-2 text-center py-6 text-gray-400 font-bold bg-gray-50 rounded-3xl border border-dashed">此音標無建議對立練習</div>
                          )}
                        </div>
                      )}

                      {activeMode === PracticeMode.SENTENCES && (
                        <div className="space-y-3">
                          {selectedPhoneme.sentences?.map((sentence, idx) => (
                            <div key={idx} className="bg-white p-5 rounded-[2rem] border-2 border-orange-50 shadow-sm text-center">
                              <p className="text-xl font-bold text-gray-700 leading-relaxed italic">"{sentence}"</p>
                            </div>
                          ))}
                        </div>
                      )}
                    </div>
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-10 w-full items-center">
                    <div className="flex flex-col items-center gap-4">
                      <MouthAnimation 
                        state={selectedPhoneme.animationState || 'neutral'} 
                        isActive={isAiSpeaking || isRecording} 
                      />
                    </div>

                    <div className="space-y-6">
                      <div className="bg-orange-50/50 backdrop-blur-sm border border-orange-100 p-8 rounded-[2.5rem] shadow-inner text-center relative min-h-[180px] flex flex-col items-center justify-center transition-all duration-300">
                         {isAiSpeaking && (
                           <div className="absolute -top-3 left-1/2 -translate-x-1/2 flex items-center gap-1.5 bg-white px-4 py-1.5 rounded-full shadow-lg border border-orange-100">
                              {[1,2,3,4,5,6].map(i => (
                                <div key={i} className={`w-1.5 h-4 bg-orange-500 rounded-full animate-bounce`} style={{ animationDelay: `${i * 0.1}s` }}></div>
                              ))}
                           </div>
                         )}
                         <p className="text-gray-800 font-bold text-xl leading-relaxed">
                           {teacherFeedback}
                         </p>
                      </div>

                      <div className="flex flex-col items-center gap-6">
                        <div className="flex items-center gap-6">
                           <button
                            onClick={toggleRecording}
                            className={`group relative flex items-center justify-center w-24 h-24 rounded-full transition-all duration-500 transform active:scale-90 ${
                              isRecording ? 'bg-red-500 shadow-red-200 shadow-2xl scale-110' : 'bg-orange-500 shadow-orange-300 shadow-2xl hover:scale-105'
                            }`}
                          >
                            {isRecording ? <div className="w-10 h-10 bg-white rounded-2xl animate-pulse"></div> : <svg xmlns="http://www.w3.org/2000/svg" className="h-12 w-12 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" /></svg>}
                            <div className={`absolute -inset-3 rounded-full border-4 ${isRecording ? 'border-red-400 animate-ping opacity-20' : 'border-transparent'}`}></div>
                          </button>

                          <button
                            onClick={handleNextPhoneme}
                            disabled={isLastPhoneme || isRecording}
                            className={`flex flex-col items-center justify-center w-20 h-20 rounded-full transition-all border-2 ${
                              isLastPhoneme || isRecording ? 'border-gray-100 bg-gray-50 text-gray-300' : 'border-orange-200 bg-white text-orange-500 hover:border-orange-500 hover:bg-orange-50 shadow-sm'
                            }`}
                          >
                             <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M13 5l7 7-7 7M5 5l7 7-7 7" /></svg>
                             <span className="text-[8px] font-black uppercase mt-1">Next</span>
                          </button>
                        </div>
                        <p className={`text-[10px] font-black tracking-[0.3em] uppercase ${isRecording ? 'text-red-500 animate-pulse' : 'text-orange-400'}`}>
                          {isRecording ? 'Recording...' : 'Tap to Practice'}
                        </p>
                      </div>
                    </div>
                  </div>
                </div>
              </div>

              {/* History Section */}
              <div className="bg-white p-8 rounded-[2.5rem] border border-orange-50 max-h-72 overflow-y-auto custom-scrollbar shadow-sm shadow-orange-50">
                <h4 className="text-[10px] font-black text-gray-400 uppercase tracking-[0.4em] mb-6 flex justify-center">Session History</h4>
                <div className="space-y-4">
                  {transcriptions.length === 0 ? <p className="text-sm text-gray-400 font-medium italic text-center py-6">準備好就點擊錄音鍵開始練習喔！老師在等你。</p> : 
                    transcriptions.map((item, idx) => (
                      <div key={idx} className={`flex ${item.role === 'model' ? 'justify-start' : 'justify-end'}`}>
                        <div className={`max-w-[85%] p-5 rounded-3xl text-sm shadow-sm transition-all hover:shadow-md ${
                          item.role === 'model' ? 'bg-white text-gray-700 rounded-tl-none border border-orange-100 font-medium' : 'bg-gradient-to-br from-orange-400 to-orange-600 text-white rounded-tr-none font-black shadow-orange-100'
                        }`}>{item.text}</div>
                      </div>
                    ))
                  }
                </div>
              </div>
            </div>
          </div>
        )}
      </main>

      <style dangerouslySetInnerHTML={{ __html: `
        .custom-scrollbar::-webkit-scrollbar { width: 5px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: #fffcf9; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #ffe7d1; border-radius: 10px; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #fb923c; }
        @keyframes fade-in { from { opacity: 0; } to { opacity: 1; } }
        @keyframes slide-in-from-bottom-4 { from { transform: translateY(1rem); } to { transform: translateY(0); } }
        @keyframes zoom-in { from { opacity: 0; transform: scale(0.95); } to { opacity: 1; transform: scale(1); } }
        .animate-in { animation: fade-in 0.5s ease-out, slide-in-from-bottom-4 0.5s ease-out; }
      `}} />
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { UserProgress } from '../types';

interface HeaderProps {
  progress?: UserProgress;
}

const Header: React.FC<HeaderProps> = ({ progress }) => {
  const [showLevelUp, setShowLevelUp] = useState(false);
  const [showPerfect, setShowPerfect] = useState(false);
  const [showBadgeAlert, setShowBadgeAlert] = useState(false);

  const prevLevelRef = useRef<number | undefined>(progress?.level);
  const prevPointsRef = useRef<number | undefined>(progress?.points);
  const prevBadgesLenRef = useRef<number | undefined>(progress?.badges.length);

  useEffect(() => {
    if (!progress) return;

    // Trigger Level Up
    if (prevLevelRef.current && progress.level > prevLevelRef.current) {
      setShowLevelUp(true);
      setTimeout(() => setShowLevelUp(false), 3000);
    }
    prevLevelRef.current = progress.level;

    // Trigger Perfect Score Reinforcement (points jump of 50 or more)
    if (prevPointsRef.current !== undefined && (progress.points - prevPointsRef.current) >= 50) {
      setShowPerfect(true);
      setTimeout(() => setShowPerfect(false), 2500);
    }
    prevPointsRef.current = progress.points;

    // Trigger Badge Mastery Alert
    if (prevBadgesLenRef.current !== undefined && progress.badges.length > prevBadgesLenRef.current) {
      setShowBadgeAlert(true);
      setTimeout(() => setShowBadgeAlert(false), 3000);
    }
    prevBadgesLenRef.current = progress.badges.length;

  }, [progress]);

  return (
    <header className="bg-white border-b border-orange-100 py-3 px-6 sticky top-0 z-50 shadow-sm backdrop-blur-md bg-white/90">
      <div className="max-w-6xl mx-auto flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="bg-orange-500 text-white p-2 rounded-xl shadow-orange-200 shadow-lg transition-transform hover:scale-110 active:scale-95">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
